{
  "name": "RhythmPulse: Ultra Precision",
  "description": "A high-fidelity rhythm precision game where every millisecond counts. Match the beat to achieve a perfect 100 score.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameState {
  IDLE = 'IDLE',
  STARTING = 'STARTING',
  PLAYING = 'PLAYING',
  RESULTS = 'RESULTS'
}

export interface ScoreEntry {
  score: number;
  timestamp: number;
  label: string;
  color: string;
}

export interface GameStats {
  totalScore: number;
  combo: number;
  maxCombo: number;
  perfects: number;
  greats: number;
  goods: number;
  misses: number;
  averageAccuracy: number;
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getAICommentary = async (stats: { perfects: number; misses: number; averageAccuracy: number }) => {
  try {
    const prompt = `You are a legendary rhythm game commentator. 
    Analyze these stats: Perfects: ${stats.perfects}, Misses: ${stats.misses}, Accuracy: ${stats.averageAccuracy.toFixed(2)}%. 
    Write a short, punchy, 1-sentence critique or praise that feels professional and high-energy. Keep it under 15 words.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.9,
        topK: 40,
        topP: 0.95,
      }
    });

    return response.text || "You have the soul of a metronome!";
  } catch (error) {
    console.error("Gemini Commentary Error:", error);
    return "The beat goes on, but your precision defines the rhythm.";
  }
};

import React, { useEffect, useRef } from 'react';

interface VisualizerProps {
  isPlaying: boolean;
  bpm: number;
  lastHitTime: number | null;
  hitScore: number | null;
}

const Visualizer: React.FC<VisualizerProps> = ({ isPlaying, bpm, lastHitTime, hitScore }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particles = useRef<Array<{ x: number, y: number, vx: number, vy: number, life: number, color: string }>>([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;

    const render = (time: number) => {
      const w = canvas.width = window.innerWidth;
      const h = canvas.height = window.innerHeight;
      const centerX = w / 2;
      const centerY = h / 2;

      ctx.clearRect(0, 0, w, h);

      // Background Pulse based on BPM
      if (isPlaying) {
        const beatDuration = 60000 / bpm;
        const phase = (time % beatDuration) / beatDuration;
        const scale = 1 + Math.pow(1 - phase, 3) * 0.1;

        // Radial gradient pulse
        const grad = ctx.createRadialGradient(centerX, centerY, 50 * scale, centerX, centerY, 500 * scale);
        grad.addColorStop(0, 'rgba(56, 189, 248, 0.1)');
        grad.addColorStop(1, 'rgba(0, 0, 0, 0)');
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, w, h);

        // Rotating Rings
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
        ctx.lineWidth = 1;
        for (let i = 0; i < 3; i++) {
          ctx.beginPath();
          const r = 200 + i * 50;
          const rotation = (time / (2000 + i * 1000)) * Math.PI * 2;
          ctx.arc(centerX, centerY, r, rotation, rotation + Math.PI * 1.5);
          ctx.stroke();
        }
      }

      // Handle Particle System for Hits
      if (lastHitTime && (time - lastHitTime < 500)) {
        const burstCount = hitScore ? Math.floor(hitScore / 10) : 5;
        if (particles.current.length < 50) {
           const color = hitScore && hitScore > 90 ? '#f0abfc' : '#38bdf8';
           for (let i = 0; i < burstCount; i++) {
             particles.current.push({
               x: centerX + (Math.random() - 0.5) * 50,
               y: centerY + (Math.random() - 0.5) * 50,
               vx: (Math.random() - 0.5) * 15,
               vy: (Math.random() - 0.5) * 15,
               life: 1.0,
               color
             });
           }
        }
      }

      // Update and Draw Particles
      particles.current = particles.current.filter(p => p.life > 0);
      particles.current.forEach(p => {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        ctx.beginPath();
        ctx.arc(p.x, p.y, 3 * p.life, 0, Math.PI * 2);
        ctx.fill();
        p.x += p.vx;
        p.y += p.vy;
        p.life -= 0.02;
      });
      ctx.globalAlpha = 1.0;

      animationFrame = requestAnimationFrame(render);
    };

    animationFrame = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animationFrame);
  }, [isPlaying, bpm, lastHitTime, hitScore]);

  return <canvas ref={canvasRef} className="absolute inset-0 z-0 pointer-events-none" />;
};

export default Visualizer;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats } from '../types';
import Visualizer from './Visualizer';
import { getAICommentary } from '../services/geminiService';

const BPM = 120;
const BEAT_INTERVAL = 60000 / BPM; // ms
const MAX_MISS_THRESHOLD = 200; // ms

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);

  const audioContext = useRef<AudioContext | null>(null);
  const startTime = useRef<number>(0);
  const nextBeatTime = useRef<number>(0);
  const hitTimeoutRef = useRef<number | null>(null);

  const playBeat = useCallback(() => {
    if (!audioContext.current) return;

    const ctx = audioContext.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(150, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.3, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.2);
  }, []);

  const startGame = async () => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }

    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0,
      combo: 0,
      maxCombo: 0,
      perfects: 0,
      greats: 0,
      goods: 0,
      misses: 0,
      averageAccuracy: 0
    });
    setAiComment("");

    setTimeout(() => {
      setGameState(GameState.PLAYING);
      startTime.current = performance.now();
      nextBeatTime.current = performance.now() + BEAT_INTERVAL;

      const interval = setInterval(() => {
        if (gameState === GameState.RESULTS) {
            clearInterval(interval);
            return;
        }
        playBeat();
      }, BEAT_INTERVAL);

      // Game ends after 30 seconds
      setTimeout(() => {
        clearInterval(interval);
        endGame();
      }, 30000);
    }, 1500);
  };

  const endGame = useCallback(async () => {
    setGameState(GameState.RESULTS);
    setLoadingAI(true);
    // Fetch AI commentary
    setStats(prev => {
        getAICommentary({
            perfects: prev.perfects,
            misses: prev.misses,
            averageAccuracy: prev.averageAccuracy
        }).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });
        return prev;
    });
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING) return;

    const tapTime = performance.now();
    const timeSinceStart = tapTime - startTime.current;

    // Calculate nearest beat
    const beatIndex = Math.round(timeSinceStart / BEAT_INTERVAL);
    const perfectBeatTime = beatIndex * BEAT_INTERVAL;
    const offset = Math.abs(timeSinceStart - perfectBeatTime);

    let score = 0;
    let label = "MISS";
    let color = "text-red-500";

    // Scoring logic: Tight curve to make 100 near impossible
    // offset in ms. 100 should be < 2ms difference.
    if (offset < 5) {
      score = 100 - (offset / 5) * 5; 
      label = "PERFECT!";
      color = "text-fuchsia-400";
    } else if (offset < 20) {
      score = 95 - ((offset - 5) / 15) * 10;
      label = "GREAT";
      color = "text-cyan-400";
    } else if (offset < 60) {
      score = 80 - ((offset - 20) / 40) * 30;
      label = "GOOD";
      color = "text-green-400";
    } else if (offset < MAX_MISS_THRESHOLD) {
      score = 40 - ((offset - 60) / (MAX_MISS_THRESHOLD - 60)) * 40;
      label = "OK";
      color = "text-yellow-500";
    } else {
      score = 0;
      label = "MISS";
      color = "text-red-500";
    }

    const finalScore = Math.max(0, Math.floor(score));

    setStats(prev => {
      const newCombo = finalScore > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + (finalScore)) / totalTaps;

      return {
        ...prev,
        totalScore: prev.totalScore + finalScore * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (finalScore >= 95 ? 1 : 0),
        greats: prev.greats + (finalScore >= 80 && finalScore < 95 ? 1 : 0),
        goods: prev.goods + (finalScore > 0 && finalScore < 80 ? 1 : 0),
        misses: prev.misses + (finalScore === 0 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score: finalScore, timestamp: tapTime, label, color });

    if (hitTimeoutRef.current) window.clearTimeout(hitTimeoutRef.current);
    hitTimeoutRef.current = window.setTimeout(() => setLastHit(null), 800);
  }, [gameState]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        handleTap();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden">
      <Visualizer 
        isPlaying={gameState === GameState.PLAYING} 
        bpm={BPM} 
        lastHitTime={lastHit?.timestamp || null}
        hitScore={lastHit?.score || null}
      />

      {/* Main UI */}
      {gameState === GameState.IDLE && (
        <div className="z-10 text-center animate-in fade-in zoom-in duration-500">
          <h1 className="text-7xl font-orbitron font-black mb-4 bg-clip-text text-transparent bg-gradient-to-r from-cyan-400 to-fuchsia-500">
            RHYTHM PULSE
          </h1>
          <p className="text-zinc-400 font-light mb-12 tracking-widest uppercase">
            Master the frequency. Match the millisecond.
          </p>
          <button 
            onClick={startGame}
            className="group relative px-8 py-4 bg-transparent border-2 border-cyan-400 text-cyan-400 font-orbitron font-bold text-xl uppercase tracking-widest hover:bg-cyan-400 hover:text-black transition-all duration-300 overflow-hidden"
          >
            <span className="relative z-10">Initialize Core</span>
            <div className="absolute inset-0 bg-cyan-400 opacity-0 group-hover:opacity-20 transition-opacity blur-xl"></div>
          </button>
        </div>
      )}

      {gameState === GameState.STARTING && (
        <div className="z-10 text-center">
          <div className="text-8xl font-orbitron font-black text-white animate-ping">
            READY
          </div>
        </div>
      )}

      {gameState === GameState.PLAYING && (
        <>
          {/* Top Info Bar */}
          <div className="absolute top-10 w-full flex justify-between px-12 z-10 font-orbitron">
            <div className="flex flex-col">
              <span className="text-xs text-zinc-500 tracking-tighter">TOTAL SCORE</span>
              <span className="text-3xl font-bold text-white">{Math.floor(stats.totalScore).toLocaleString()}</span>
            </div>
            <div className="flex flex-col items-end">
              <span className="text-xs text-zinc-500 tracking-tighter">PRECISION</span>
              <span className="text-3xl font-bold text-cyan-400">{stats.averageAccuracy.toFixed(1)}%</span>
            </div>
          </div>

          {/* Center Feedback */}
          <div className="z-10 flex flex-col items-center pointer-events-none select-none">
            <div className={`text-5xl font-orbitron font-black mb-2 transition-all duration-75 transform ${lastHit ? 'scale-110 opacity-100' : 'scale-100 opacity-0'} ${lastHit?.color}`}>
              {lastHit?.label}
            </div>
            {lastHit && (
              <div className="text-2xl font-orbitron font-bold text-white/50">
                {lastHit.score}
              </div>
            )}

            <div className="mt-12 flex flex-col items-center">
                <div className="text-8xl font-orbitron font-black text-white/10 relative">
                    {stats.combo > 0 && stats.combo}
                    {stats.combo > 10 && <span className="absolute -top-4 -right-12 text-sm text-fuchsia-500 animate-pulse">FEVER x{(1 + Math.floor(stats.combo / 10) * 0.1).toFixed(1)}</span>}
                </div>
                {stats.combo > 0 && <span className="text-xs font-orbitron text-zinc-600 tracking-widest -mt-2 uppercase">Combo</span>}
            </div>
          </div>

          {/* Bottom Hit Bar */}
          <div className="absolute bottom-32 w-full flex flex-col items-center z-10">
            <div className="w-64 h-2 bg-zinc-900 rounded-full overflow-hidden relative border border-white/5">
                <div className="absolute top-0 bottom-0 left-1/2 w-1 bg-cyan-400 shadow-[0_0_10px_cyan] transform -translate-x-1/2"></div>
                {/* Simulated beat pulses could go here if needed */}
            </div>
            <span className="mt-4 text-[10px] font-orbitron text-zinc-500 tracking-widest uppercase">Spacebar to Sync</span>
          </div>
        </>
      )}

      {gameState === GameState.RESULTS && (
        <div className="z-20 w-full max-w-2xl bg-black/80 backdrop-blur-xl border border-white/10 p-12 rounded-2xl shadow-2xl animate-in fade-in zoom-in slide-in-from-bottom-12 duration-700">
          <div className="flex justify-between items-center mb-12">
            <h2 className="text-4xl font-orbitron font-black text-white">SESSION COMPLETE</h2>
            <div className="text-right">
                <div className="text-xs text-zinc-500 font-orbitron">FINAL SCORE</div>
                <div className="text-3xl font-orbitron font-bold text-cyan-400">{Math.floor(stats.totalScore).toLocaleString()}</div>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-8 mb-12 font-orbitron">
            <div className="space-y-4">
                <StatLine label="Perfect" value={stats.perfects} color="text-fuchsia-400" />
                <StatLine label="Great" value={stats.greats} color="text-cyan-400" />
                <StatLine label="Good" value={stats.goods} color="text-green-400" />
                <StatLine label="Miss" value={stats.misses} color="text-red-500" />
            </div>
            <div className="space-y-4 border-l border-white/5 pl-8">
                <div className="flex justify-between items-end">
                    <span className="text-xs text-zinc-500 uppercase">Max Combo</span>
                    <span className="text-2xl font-bold text-white">{stats.maxCombo}</span>
                </div>
                <div className="flex justify-between items-end">
                    <span className="text-xs text-zinc-500 uppercase">Avg. Accuracy</span>
                    <span className="text-2xl font-bold text-cyan-400">{stats.averageAccuracy.toFixed(2)}%</span>
                </div>
            </div>
          </div>

          {/* AI Commentary */}
          <div className="p-6 bg-zinc-900/50 rounded-xl mb-12 border border-white/5 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-cyan-400 to-fuchsia-500"></div>
            <div className="text-[10px] font-orbitron text-zinc-500 uppercase tracking-widest mb-2">Neural Link Analysis</div>
            <div className="text-xl font-light italic text-zinc-200">
                {loadingAI ? (
                    <div className="flex items-center space-x-2">
                        <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                        <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                    </div>
                ) : aiComment}
            </div>
          </div>

          <button 
            onClick={startGame}
            className="w-full py-4 bg-white text-black font-orbitron font-black text-xl hover:bg-cyan-400 transition-colors"
          >
            RE-INITIALIZE
          </button>
        </div>
      )}
    </div>
  );
};

const StatLine: React.FC<{ label: string, value: number, color: string }> = ({ label, value, color }) => (
    <div className="flex justify-between items-center">
        <span className="text-xs text-zinc-500 uppercase tracking-widest">{label}</span>
        <span className={`text-xl font-bold ${color}`}>{value}</span>
    </div>
);

export default RhythmEngine;

