import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [selectedLevel, setSelectedLevel] = useState<Level | null>(null);
  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const nextNoteTime = useRef<number>(0.0);
  const currentBeatInPattern = useRef<number>(0); // Index in the level.pattern array
  const timerID = useRef<number | null>(null);

  // Queue for scoring: { time: absoluteAudioTime, processed: boolean }
  const expectedHits = useRef<Array<{ time: number, processed: boolean }>>([]);

  // Visualizer Refs
  const [loopProgress, setLoopProgress] = useState(0);
  const [beatTrigger, setBeatTrigger] = useState(0);
  const loopStartTime = useRef<number>(0);

  const playSound = useCallback((time: number, isAccent: boolean) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    // Synth Kick/Bleep
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = isAccent ? 'triangle' : 'sine';
    const freq = isAccent ? 220 : 150;
    osc.frequency.setValueAtTime(freq, time);
    osc.frequency.exponentialRampToValueAtTime(40, time + 0.1);

    gain.gain.setValueAtTime(isAccent ? 0.5 : 0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    // Add to scoring queue
    expectedHits.current.push({ time: time, processed: false });

    // Clean up old expected hits (older than 0.5s)
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);

    // Play Audio
    // Determine if it's the "1" count (first beat of loop) for accent
    const isOne = beatNumber === 0;
    playSound(time, isOne);

    // Trigger Visual Pulse (React state update for visualizer)
    // We use a timeout to sync the state update with the audio time roughly
    const timeToNote = (time - (audioContext.current?.currentTime || 0)) * 1000;
    setTimeout(() => {
        setBeatTrigger(prev => prev + 1);
    }, Math.max(0, timeToNote));

  }, [playSound]);

  const scheduler = useCallback(() => {
    if (!selectedLevel || !audioContext.current) return;

    // While there are notes that will need to play before the next interval,
    // schedule them and advance the pointer.
    while (nextNoteTime.current < audioContext.current.currentTime + SCHEDULE_AHEAD_TIME) {

        // Schedule current note based on pattern
        const pattern = selectedLevel.pattern;
        const beatDuration = 60 / selectedLevel.bpm;

        // Determine the beat offset from the start of the pattern for the NEXT note
        // Current logic: We are at `currentBeatInPattern` index.

        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);

        // Advance
        const currentBeatVal = pattern[currentBeatInPattern.current];
        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];

        // Calculate time diff in beats
        let beatDiff = 0;
        if (nextIndex === 0) {
            // Wrapped around
            beatDiff = selectedLevel.loopBeats - currentBeatVal + nextBeatVal;
            // Also reset loop start time reference for visualizer when wrapping
            // (Approximation for visuals)
            loopStartTime.current = nextNoteTime.current + (beatDiff * beatDuration);
        } else {
            beatDiff = nextBeatVal - currentBeatVal;
        }

        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }

    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [selectedLevel, scheduleNote]);

  // Visualizer Loop Progress Updater
  useEffect(() => {
    if (gameState !== GameState.PLAYING || !selectedLevel || !audioContext.current) return;

    let animFrame: number;
    const updateVisuals = () => {
        if (!audioContext.current || !selectedLevel) return;
        const now = audioContext.current.currentTime;
        const beatDuration = 60 / selectedLevel.bpm;
        const loopDuration = beatDuration * selectedLevel.loopBeats;

        // Calculate progress based on loop modulo
        // We need a stable start time reference. 
        // Simple modulo of total time works well for circular buffers.
        const progress = (now % loopDuration) / loopDuration;
        setLoopProgress(progress);

        animFrame = requestAnimationFrame(updateVisuals);
    };
    animFrame = requestAnimationFrame(updateVisuals);
    return () => cancelAnimationFrame(animFrame);
  }, [gameState, selectedLevel]);

  const selectLevel = (level: Level) => {
      setSelectedLevel(level);
      startGame(level);
  };

  const startGame = async (level: Level) => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0,
      combo: 0,
      maxCombo: 0,
      perfects: 0,
      greats: 0,
      goods: 0,
      misses: 0,
      averageAccuracy: 0
    });
    setAiComment("");
    expectedHits.current = [];

    setTimeout(() => {
      setGameState(GameState.PLAYING);
      if (audioContext.current) {
          nextNoteTime.current = audioContext.current.currentTime + 0.1;
          currentBeatInPattern.current = 0; // Start at first beat of pattern
          loopStartTime.current = nextNoteTime.current;
          scheduler();
      }

      // Game Duration: 30s
      setTimeout(() => {
        if (timerID.current) clearTimeout(timerID.current);
        endGame();
      }, 30000);
    }, 1500);
  };

  const endGame = useCallback(async () => {
    setGameState(GameState.RESULTS);
    setLoadingAI(true);
    setStats(prev => {
        getAICommentary({
            perfects: prev.perfects,
            misses: prev.misses,
            averageAccuracy: prev.averageAccuracy
        }).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });
        return prev;
    });
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current) return;

    const tapTime = audioContext.current.currentTime;

    // Find nearest expected hit
    // Filter to hits that haven't been processed
    const activeHits = expectedHits.current.filter(h => !h.processed);

    // Find closest
    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) {
            minDiff = diff;
            closestHit = hit;
        }
    }

    // If closest hit is too far (e.g. > 0.2s), ignore or count as miss?
    // Let's count as miss if nothing is close, or just ignore spam.
    // Let's implement a "window" of 200ms (0.2s)

    const diffMs = minDiff * 1000;

    let score = 0;
    let label = "MISS";
    let color = "text-red-500";
    let isHit = false;

    if (closestHit && diffMs < 200) {
        closestHit.processed = true;
        isHit = true;

        if (diffMs < 20) { // Extremely tight for 100
             score = 100;
             label = "PERFECT+";
             color = `text-white drop-shadow-[0_0_10px_white]`;
        } else if (diffMs < 45) {
             score = 90 + Math.floor((45 - diffMs)/2.5);
             label = "PERFECT";
             color = `text-${selectedLevel?.color}-300`;
        } else if (diffMs < 90) {
             score = 70 + Math.floor((90 - diffMs)/2.25);
             label = "GREAT";
             color = `text-${selectedLevel?.color}-400`;
        } else if (diffMs < 150) {
             score = 40 + Math.floor((150 - diffMs)/2);
             label = "GOOD";
             color = "text-yellow-400";
        } else {
             score = 10;
             label = "EARLY/LATE";
             color = "text-zinc-500";
        }
    } else {
        // Whiff
        score = 0;
        label = "MISS";
        color = "text-red-600";
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;

      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });

    // Auto-clear hit feedback after a delay
    // Note: We use a stable ID logic inside the visualizer or just let React rerender

  }, [gameState, selectedLevel]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        handleTap();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden">
      {/* Background Visualizer Layer */}
      {gameState !== GameState.IDLE && selectedLevel && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            bpm={selectedLevel.bpm}
            level={selectedLevel}
            currentTime={audioContext.current?.currentTime || 0}
            loopProgress={loopProgress}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {/* --- IDLE STATE: LEVEL SELECTOR --- */}
      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {/* --- STARTING STATE --- */}
      {gameState === GameState.STARTING && selectedLevel && (
        <div className="z-10 text-center">
           <div className={`text-2xl font-orbitron text-${selectedLevel.color}-400 mb-4 tracking-widest uppercase`}>Syncing Neural Link...</div>
           <div className="text-9xl font-orbitron font-black text-white animate-pulse">
            GET READY
          </div>
        </div>
      )}

      {/* --- PLAYING STATE --- */}
      {gameState === GameState.PLAYING && selectedLevel && (
        <>
          {/* Top HUD */}
          <div className="absolute top-0 left-0 w-full p-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className={`px-3 py-1 bg-${selectedLevel.color}-500/20 border border-${selectedLevel.color}-500/50 rounded text-xs font-orbitron text-${selectedLevel.color}-300 tracking-widest mb-2`}>
                     {selectedLevel.name.toUpperCase()}
                 </div>
                 <div className="text-4xl font-orbitron font-bold text-white tracking-tighter">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className="text-xs font-orbitron text-zinc-400 tracking-widest mb-1">ACCURACY</div>
                 <div className={`text-4xl font-orbitron font-bold ${stats.averageAccuracy > 90 ? 'text-white' : `text-${selectedLevel.color}-400`}`}>
                     {stats.averageAccuracy.toFixed(1)}%
                 </div>
             </div>
          </div>

          {/* Center Hit Feedback */}
          <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
             {/* Note: The visualizer handles the ring. We handle the text here. */}
             <div className={`text-6xl font-orbitron font-black transition-all duration-75 transform ${lastHit ? 'scale-110 opacity-100 translate-y-0' : 'scale-90 opacity-0 translate-y-4'} ${lastHit?.color}`} style={{ textShadow: '0 0 30px currentColor' }}>
               {lastHit?.label}
             </div>
             {lastHit && lastHit.score > 0 && (
                 <div className="text-xl font-orbitron text-white mt-2 tracking-widest">
                     +{lastHit.score}
                 </div>
             )}
          </div>

          {/* Combo Counter (Floating) */}
          {stats.combo > 5 && (
              <div className="absolute bottom-1/4 z-10 animate-bounce">
                  <div className={`text-5xl font-orbitron font-black text-${selectedLevel.color}-500 opacity-50`}>
                      {stats.combo} COMBO
                  </div>
              </div>
          )}

          {/* Bottom Prompt */}
          <div className="absolute bottom-12 w-full text-center z-10 opacity-50">
             <span className="text-[10px] font-orbitron text-white tracking-[1em] uppercase">Press Space to Rhythm</span>
          </div>
        </>
      )}

      {/* --- RESULTS STATE --- */}
      {gameState === GameState.RESULTS && (
        <div className="z-20 w-full max-w-2xl bg-zinc-950/90 backdrop-blur-2xl border border-white/10 p-12 rounded-3xl shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-500">
          <div className="flex justify-between items-center mb-12 border-b border-white/10 pb-8">
            <h2 className="text-4xl font-orbitron font-black text-white tracking-tight">SESSION REPORT</h2>
            <div className={`px-4 py-2 bg-${selectedLevel?.color || 'cyan'}-900/30 rounded border border-${selectedLevel?.color || 'cyan'}-500/30 text-${selectedLevel?.color || 'cyan'}-300 font-orbitron text-sm`}>
                {selectedLevel?.name}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-12 mb-12 font-orbitron">
             <div className="flex flex-col justify-center space-y-6">
                 <StatRow label="PERFECT" count={stats.perfects} total={stats.totalScore} color="text-white" />
                 <StatRow label="GREAT" count={stats.greats} total={stats.totalScore} color={`text-${selectedLevel?.color}-300`} />
                 <StatRow label="GOOD" count={stats.goods} total={stats.totalScore} color="text-yellow-500" />
                 <StatRow label="MISS" count={stats.misses} total={stats.totalScore} color="text-red-500" />
             </div>

             <div className="flex flex-col justify-center items-center bg-white/5 rounded-2xl p-6">
                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Accuracy</div>
                 <div className="text-6xl font-bold text-white mb-6">{stats.averageAccuracy.toFixed(1)}%</div>

                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Max Combo</div>
                 <div className={`text-4xl font-bold text-${selectedLevel?.color}-400`}>{stats.maxCombo}</div>
             </div>
          </div>

          {/* AI Commentary */}
          <div className="p-6 bg-gradient-to-r from-zinc-900 to-black rounded-xl mb-8 border-l-4 border-white/20">
            <div className="text-[10px] font-orbitron text-zinc-500 uppercase tracking-widest mb-2">System Analysis</div>
            <div className="text-lg font-light italic text-zinc-300 min-h-[1.5em]">
                {loadingAI ? "Analyzing rhythm patterns..." : `"${aiComment}"`}
            </div>
          </div>

          <div className="flex space-x-4">
             <button 
                onClick={() => setGameState(GameState.IDLE)}
                className="flex-1 py-4 border border-white/20 text-white font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-white/10 transition-colors rounded"
              >
                Select Level
              </button>
              <button 
                onClick={() => selectedLevel && startGame(selectedLevel)}
                className={`flex-1 py-4 bg-${selectedLevel?.color || 'cyan'}-500 text-black font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-${selectedLevel?.color || 'cyan'}-400 transition-colors rounded shadow-[0_0_20px_rgba(34,211,238,0.3)]`}
              >
                Retry
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

const StatRow = ({ label, count, total, color }: { label: string, count: number, total: number, color: string }) => (
    <div className="flex justify-between items-center group">
        <span className="text-zinc-500 text-sm font-bold tracking-widest group-hover:text-white transition-colors">{label}</span>
        <span className={`text-2xl font-bold ${color}`}>{count}</span>
    </div>
);

export default RhythmEngine;

import React, { useEffect, useRef } from 'react';
import { Level } from '../types';

interface VisualizerProps {
  isPlaying: boolean;
  level: Level;
  audioContext: AudioContext | null;
  loopStartTime: number; // The timestamp of "Beat 0" to sync phase
  lastHitTime: number | null;
  hitScore: number | null;
  beatTrigger: number; // Still useful for pulse effects
}

const Visualizer: React.FC<VisualizerProps> = ({ 
  isPlaying, 
  level, 
  audioContext,
  loopStartTime,
  lastHitTime, 
  hitScore,
  beatTrigger 
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particles = useRef<Array<{ x: number, y: number, vx: number, vy: number, life: number, color: string, size: number }>>([]);
  const pulseRef = useRef(0);
  const lastBeatRef = useRef(beatTrigger);

  // Helper to convert beat position to angle (0 is top, clockwise)
  const getAngle = (beat: number, totalBeats: number) => {
    return (beat / totalBeats) * Math.PI * 2 - Math.PI / 2;
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;

    const render = () => {
      const w = canvas.width = window.innerWidth;
      const h = canvas.height = window.innerHeight;
      const cx = w / 2;
      const cy = h / 2;
      // Radius of the main rhythm circle
      const r = Math.min(w, h) * 0.35; 

      // Calculate Loop Progress internally for 60fps smoothness without React renders
      let loopProgress = 0;
      if (isPlaying && audioContext) {
          const now = audioContext.currentTime;
          const beatDuration = 60 / level.bpm;
          const loopDuration = beatDuration * level.loopBeats;
          // Calculate phase-aligned progress
          // We add loopDuration to (now - start) before modulo to handle potential negative small numbers at start
          loopProgress = ((now - loopStartTime) % loopDuration) / loopDuration;
          if (loopProgress < 0) loopProgress += 1;
      } else {
          // Idle rotation
          loopProgress = (Date.now() % 5000) / 5000;
      }

      ctx.clearRect(0, 0, w, h);

      // Handle Pulse on Beat
      if (beatTrigger !== lastBeatRef.current) {
        pulseRef.current = 1.0;
        lastBeatRef.current = beatTrigger;
      }
      pulseRef.current = Math.max(0, pulseRef.current - 0.05);

      // --- Background & Atmosphere ---
      const bgGrad = ctx.createRadialGradient(cx, cy, r * 0.5, cx, cy, w);
      bgGrad.addColorStop(0, `${level.hex}11`);
      bgGrad.addColorStop(1, '#000000');
      ctx.fillStyle = bgGrad;
      ctx.fillRect(0, 0, w, h);

      if (isPlaying) {
        // --- The Rhythm Track (Circle) ---
        ctx.beginPath();
        ctx.arc(cx, cy, r, 0, Math.PI * 2);
        ctx.strokeStyle = '#333';
        ctx.lineWidth = 2;
        ctx.stroke();

        // Glow effect on track
        ctx.shadowBlur = 15;
        ctx.shadowColor = level.hex;
        ctx.beginPath();
        ctx.arc(cx, cy, r, 0, Math.PI * 2);
        ctx.strokeStyle = `${level.hex}33`; // Transparent level color
        ctx.lineWidth = 4 + pulseRef.current * 4;
        ctx.stroke();
        ctx.shadowBlur = 0;

        // --- Beat Markers (The Nodes) ---
        level.pattern.forEach(beat => {
          const angle = getAngle(beat, level.loopBeats);
          const x = cx + Math.cos(angle) * r;
          const y = cy + Math.sin(angle) * r;

          // Active Glow Check
          const nodeProgress = beat / level.loopBeats;
          let diff = Math.abs(loopProgress - nodeProgress);
          if (diff > 0.5) diff = 1 - diff; // Handle wrap-around

          // Flash when cursor passes
          const isActive = diff < 0.03; 

          ctx.beginPath();
          ctx.arc(x, y, isActive ? 12 : 6, 0, Math.PI * 2);
          ctx.fillStyle = isActive ? '#ffffff' : level.hex;
          ctx.fill();

          if (isActive) {
            ctx.shadowBlur = 20;
            ctx.shadowColor = '#ffffff';
            ctx.beginPath();
            ctx.arc(x, y, 20, 0, Math.PI * 2);
            ctx.fillStyle = `${level.hex}66`;
            ctx.fill();
            ctx.shadowBlur = 0;
          }
        });

        // --- The Cursor (Sweeping Radar) ---
        const cursorAngle = (loopProgress * Math.PI * 2) - Math.PI / 2;
        const cursorX = cx + Math.cos(cursorAngle) * r;
        const cursorY = cy + Math.sin(cursorAngle) * r;

        // Draw Line to cursor
        const grad = ctx.createLinearGradient(cx, cy, cursorX, cursorY);
        grad.addColorStop(0, 'transparent');
        grad.addColorStop(1, '#ffffff');
        ctx.beginPath();
        ctx.moveTo(cx, cy);
        ctx.lineTo(cursorX, cursorY);
        ctx.strokeStyle = grad;
        ctx.lineWidth = 2;
        ctx.stroke();

        // Draw Cursor Head
        ctx.beginPath();
        ctx.arc(cursorX, cursorY, 8, 0, Math.PI * 2);
        ctx.fillStyle = '#ffffff';
        ctx.fill();
      }

      // --- Particle System (Hits) ---
      particles.current = particles.current.filter(p => p.life > 0);
      particles.current.forEach(p => {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI * 2);
        ctx.fill();
        p.x += p.vx;
        p.y += p.vy;
        p.life -= 0.03;
      });
      ctx.globalAlpha = 1.0;

      animationFrame = requestAnimationFrame(render);
    };

    animationFrame = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animationFrame);
  }, [isPlaying, level, loopStartTime, audioContext, beatTrigger]);

  // Handle particle spawns from prop changes
  useEffect(() => {
     if (hitScore !== null && hitScore !== undefined) {
         const w = canvasRef.current?.width || window.innerWidth;
         const h = canvasRef.current?.height || window.innerHeight;
         const cx = w/2;
         const cy = h/2;
         const count = Math.floor(hitScore / 5) + 5;
         const color = hitScore > 90 ? '#ffffff' : level.hex;

         for(let i=0; i<count; i++) {
             const angle = Math.random() * Math.PI * 2;
             const speed = Math.random() * 10 + 5;
             particles.current.push({
                 x: cx,
                 y: cy,
                 vx: Math.cos(angle) * speed,
                 vy: Math.sin(angle) * speed,
                 life: 1.0,
                 color: color,
                 size: Math.random() * 3 + 1
             });
         }
     }
  }, [lastHitTime, hitScore, level.hex]);

  return <canvas ref={canvasRef} className="absolute inset-0 z-0 pointer-events-none" />;
};

export default Visualizer;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [selectedLevel, setSelectedLevel] = useState<Level | null>(null);
  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const nextNoteTime = useRef<number>(0.0);
  const currentBeatInPattern = useRef<number>(0);
  const timerID = useRef<number | null>(null);
  const loopStartTime = useRef<number>(0);

  // Queue for scoring
  const expectedHits = useRef<Array<{ time: number, processed: boolean }>>([]);

  // Visualizer Refs (Only triggered on beats/events, not every frame)
  const [beatTrigger, setBeatTrigger] = useState(0);

  const playSound = useCallback((time: number, isAccent: boolean) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    // Create sound
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = isAccent ? 'triangle' : 'sine';
    const freq = isAccent ? 220 : 150;
    osc.frequency.setValueAtTime(freq, time);
    osc.frequency.exponentialRampToValueAtTime(40, time + 0.1);

    gain.gain.setValueAtTime(isAccent ? 0.5 : 0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    // Add to scoring queue
    expectedHits.current.push({ time: time, processed: false });

    // Clean up old expected hits
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);

    // Play Audio
    const isOne = beatNumber === 0;
    playSound(time, isOne);

    // Trigger Visual Pulse (React state update for visualizer)
    const timeToNote = (time - (audioContext.current?.currentTime || 0)) * 1000;
    setTimeout(() => {
        setBeatTrigger(prev => prev + 1);
    }, Math.max(0, timeToNote));

  }, [playSound]);

  const scheduler = useCallback(() => {
    if (!selectedLevel || !audioContext.current) return;

    while (nextNoteTime.current < audioContext.current.currentTime + SCHEDULE_AHEAD_TIME) {

        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);

        // Advance to next note
        const pattern = selectedLevel.pattern;
        const beatDuration = 60 / selectedLevel.bpm;
        const currentBeatVal = pattern[currentBeatInPattern.current];

        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];

        let beatDiff = 0;
        if (nextIndex === 0) {
            // Wrapped around loop
            beatDiff = selectedLevel.loopBeats - currentBeatVal + nextBeatVal;
        } else {
            beatDiff = nextBeatVal - currentBeatVal;
        }

        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }

    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [selectedLevel, scheduleNote]);

  // Start/Stop Scheduler based on GameState
  useEffect(() => {
      if (gameState === GameState.PLAYING && selectedLevel && audioContext.current) {
          // Start the scheduler loop
          scheduler();
      }
      return () => {
          if (timerID.current) window.clearTimeout(timerID.current);
      };
  }, [gameState, selectedLevel, scheduler]);

  const selectLevel = (level: Level) => {
      setSelectedLevel(level);
      startGame(level);
  };

  const startGame = async (level: Level) => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    // Ensure context is running (must be done on user gesture)
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0,
      combo: 0,
      maxCombo: 0,
      perfects: 0,
      greats: 0,
      goods: 0,
      misses: 0,
      averageAccuracy: 0
    });
    setAiComment("");
    setLastHit(null);
    expectedHits.current = [];

    setTimeout(() => {
      // Setup timing for immediate start
      if (audioContext.current) {
          const now = audioContext.current.currentTime;
          // Start a fraction in the future to allow scheduler to catch up
          nextNoteTime.current = now + 0.1; 
          loopStartTime.current = nextNoteTime.current;
          currentBeatInPattern.current = 0;
      }

      setGameState(GameState.PLAYING);

      // Auto-end game after duration
      setTimeout(() => {
        // Only end if we are still playing (not manually reset)
        setGameState(prev => prev === GameState.PLAYING ? GameState.RESULTS : prev);
      }, 30000);
    }, 1500);
  };

  useEffect(() => {
      if (gameState === GameState.RESULTS) {
          endGame();
      }
  }, [gameState]);

  const endGame = useCallback(async () => {
    setLoadingAI(true);
    setStats(prev => {
        // Trigger AI Commentary
        getAICommentary({
            perfects: prev.perfects,
            misses: prev.misses,
            averageAccuracy: prev.averageAccuracy
        }).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });
        return prev;
    });
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current) return;

    const tapTime = audioContext.current.currentTime;

    // Scoring Logic
    const activeHits = expectedHits.current.filter(h => !h.processed);

    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) {
            minDiff = diff;
            closestHit = hit;
        }
    }

    const diffMs = minDiff * 1000;

    let score = 0;
    let label = "MISS";
    let color = "text-red-500";

    if (closestHit && diffMs < 200) {
        closestHit.processed = true;

        if (diffMs < 20) {
             score = 100;
             label = "PERFECT+";
             color = `text-white drop-shadow-[0_0_10px_white]`;
        } else if (diffMs < 45) {
             score = 90 + Math.floor((45 - diffMs)/2.5);
             label = "PERFECT";
             color = `text-${selectedLevel?.color}-300`;
        } else if (diffMs < 90) {
             score = 70 + Math.floor((90 - diffMs)/2.25);
             label = "GREAT";
             color = `text-${selectedLevel?.color}-400`;
        } else if (diffMs < 150) {
             score = 40 + Math.floor((150 - diffMs)/2);
             label = "GOOD";
             color = "text-yellow-400";
        } else {
             score = 10;
             label = "EARLY/LATE";
             color = "text-zinc-500";
        }
    } else {
        score = 0;
        label = "MISS";
        color = "text-red-600";
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;

      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, selectedLevel]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        handleTap();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden">
      {/* Background Visualizer Layer */}
      {gameState !== GameState.IDLE && selectedLevel && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={selectedLevel}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {/* --- IDLE STATE: LEVEL SELECTOR --- */}
      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {/* --- STARTING STATE --- */}
      {gameState === GameState.STARTING && selectedLevel && (
        <div className="z-10 text-center">
           <div className={`text-2xl font-orbitron text-${selectedLevel.color}-400 mb-4 tracking-widest uppercase`}>Syncing Neural Link...</div>
           <div className="text-9xl font-orbitron font-black text-white animate-pulse">
            GET READY
          </div>
        </div>
      )}

      {/* --- PLAYING STATE --- */}
      {gameState === GameState.PLAYING && selectedLevel && (
        <>
          {/* Top HUD */}
          <div className="absolute top-0 left-0 w-full p-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className={`px-3 py-1 bg-${selectedLevel.color}-500/20 border border-${selectedLevel.color}-500/50 rounded text-xs font-orbitron text-${selectedLevel.color}-300 tracking-widest mb-2`}>
                     {selectedLevel.name.toUpperCase()}
                 </div>
                 <div className="text-4xl font-orbitron font-bold text-white tracking-tighter">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className="text-xs font-orbitron text-zinc-400 tracking-widest mb-1">ACCURACY</div>
                 <div className={`text-4xl font-orbitron font-bold ${stats.averageAccuracy > 90 ? 'text-white' : `text-${selectedLevel.color}-400`}`}>
                     {stats.averageAccuracy.toFixed(1)}%
                 </div>
             </div>
          </div>

          {/* Center Hit Feedback */}
          <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
             <div className={`text-6xl font-orbitron font-black transition-all duration-75 transform ${lastHit ? 'scale-110 opacity-100 translate-y-0' : 'scale-90 opacity-0 translate-y-4'} ${lastHit?.color}`} style={{ textShadow: '0 0 30px currentColor' }}>
               {lastHit?.label}
             </div>
             {lastHit && lastHit.score > 0 && (
                 <div className="text-xl font-orbitron text-white mt-2 tracking-widest">
                     +{lastHit.score}
                 </div>
             )}
          </div>

          {/* Combo Counter (Floating) */}
          {stats.combo > 5 && (
              <div className="absolute bottom-1/4 z-10 animate-bounce">
                  <div className={`text-5xl font-orbitron font-black text-${selectedLevel.color}-500 opacity-50`}>
                      {stats.combo} COMBO
                  </div>
              </div>
          )}

          {/* Bottom Prompt */}
          <div className="absolute bottom-12 w-full text-center z-10 opacity-50">
             <span className="text-[10px] font-orbitron text-white tracking-[1em] uppercase">Press Space to Rhythm</span>
          </div>
        </>
      )}

      {/* --- RESULTS STATE --- */}
      {gameState === GameState.RESULTS && (
        <div className="z-20 w-full max-w-2xl bg-zinc-950/90 backdrop-blur-2xl border border-white/10 p-12 rounded-3xl shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-500">
          <div className="flex justify-between items-center mb-12 border-b border-white/10 pb-8">
            <h2 className="text-4xl font-orbitron font-black text-white tracking-tight">SESSION REPORT</h2>
            <div className={`px-4 py-2 bg-${selectedLevel?.color || 'cyan'}-900/30 rounded border border-${selectedLevel?.color || 'cyan'}-500/30 text-${selectedLevel?.color || 'cyan'}-300 font-orbitron text-sm`}>
                {selectedLevel?.name}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-12 mb-12 font-orbitron">
             <div className="flex flex-col justify-center space-y-6">
                 <StatRow label="PERFECT" count={stats.perfects} total={stats.totalScore} color="text-white" />
                 <StatRow label="GREAT" count={stats.greats} total={stats.totalScore} color={`text-${selectedLevel?.color}-300`} />
                 <StatRow label="GOOD" count={stats.goods} total={stats.totalScore} color="text-yellow-500" />
                 <StatRow label="MISS" count={stats.misses} total={stats.totalScore} color="text-red-500" />
             </div>

             <div className="flex flex-col justify-center items-center bg-white/5 rounded-2xl p-6">
                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Accuracy</div>
                 <div className="text-6xl font-bold text-white mb-6">{stats.averageAccuracy.toFixed(1)}%</div>

                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Max Combo</div>
                 <div className={`text-4xl font-bold text-${selectedLevel?.color}-400`}>{stats.maxCombo}</div>
             </div>
          </div>

          {/* AI Commentary */}
          <div className="p-6 bg-gradient-to-r from-zinc-900 to-black rounded-xl mb-8 border-l-4 border-white/20">
            <div className="text-[10px] font-orbitron text-zinc-500 uppercase tracking-widest mb-2">System Analysis</div>
            <div className="text-lg font-light italic text-zinc-300 min-h-[1.5em]">
                {loadingAI ? "Analyzing rhythm patterns..." : `"${aiComment}"`}
            </div>
          </div>

          <div className="flex space-x-4">
             <button 
                onClick={() => setGameState(GameState.IDLE)}
                className="flex-1 py-4 border border-white/20 text-white font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-white/10 transition-colors rounded"
              >
                Select Level
              </button>
              <button 
                onClick={() => selectedLevel && startGame(selectedLevel)}
                className={`flex-1 py-4 bg-${selectedLevel?.color || 'cyan'}-500 text-black font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-${selectedLevel?.color || 'cyan'}-400 transition-colors rounded shadow-[0_0_20px_rgba(34,211,238,0.3)]`}
              >
                Retry
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

const StatRow = ({ label, count, total, color }: { label: string, count: number, total: number, color: string }) => (
    <div className="flex justify-between items-center group">
        <span className="text-zinc-500 text-sm font-bold tracking-widest group-hover:text-white transition-colors">{label}</span>
        <span className={`text-2xl font-bold ${color}`}>{count}</span>
    </div>
);

