    let score = 0;
    let label = "MISS";
    let color = "text-red-500";

    if (closestHit && diffMs < 200) {
        closestHit.processed = true;

        if (diffMs < 20) {
             score = 100;
             label = "PERFECT+";
             color = `text-white drop-shadow-[0_0_10px_white]`;
        } else if (diffMs < 45) {
             score = 90 + Math.floor((45 - diffMs)/2.5);
             label = "PERFECT";
             color = `text-${selectedLevel?.color}-300`;
        } else if (diffMs < 90) {
             score = 70 + Math.floor((90 - diffMs)/2.25);
             label = "GREAT";
             color = `text-${selectedLevel?.color}-400`;
        } else if (diffMs < 150) {
             score = 40 + Math.floor((150 - diffMs)/2);
             label = "GOOD";
             color = "text-yellow-400";
        } else {
             score = 10;
             label = "EARLY/LATE";
             color = "text-zinc-500";
        }
    } else {
        score = 0;
        label = "MISS";
        color = "text-red-600";
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;

      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, selectedLevel]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        handleTap();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden">
      {/* Background Visualizer Layer */}
      {gameState !== GameState.IDLE && selectedLevel && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={selectedLevel}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {/* --- IDLE STATE: LEVEL SELECTOR --- */}
      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {/* --- STARTING STATE --- */}
      {gameState === GameState.STARTING && selectedLevel && (
        <div className="z-10 text-center">
           <div className={`text-2xl font-orbitron text-${selectedLevel.color}-400 mb-4 tracking-widest uppercase`}>Syncing Neural Link...</div>
           <div className="text-9xl font-orbitron font-black text-white animate-pulse">
            GET READY
          </div>
        </div>
      )}

      {/* --- PLAYING STATE --- */}
      {gameState === GameState.PLAYING && selectedLevel && (
        <>
          {/* Top HUD */}
          <div className="absolute top-0 left-0 w-full p-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className={`px-3 py-1 bg-${selectedLevel.color}-500/20 border border-${selectedLevel.color}-500/50 rounded text-xs font-orbitron text-${selectedLevel.color}-300 tracking-widest mb-2`}>
                     {selectedLevel.name.toUpperCase()}
                 </div>
                 <div className="text-4xl font-orbitron font-bold text-white tracking-tighter">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className="text-xs font-orbitron text-zinc-400 tracking-widest mb-1">ACCURACY</div>
                 <div className={`text-4xl font-orbitron font-bold ${stats.averageAccuracy > 90 ? 'text-white' : `text-${selectedLevel.color}-400`}`}>
                     {stats.averageAccuracy.toFixed(1)}%
                 </div>
             </div>
          </div>

          {/* Center Hit Feedback */}
          <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
             <div className={`text-6xl font-orbitron font-black transition-all duration-75 transform ${lastHit ? 'scale-110 opacity-100 translate-y-0' : 'scale-90 opacity-0 translate-y-4'} ${lastHit?.color}`} style={{ textShadow: '0 0 30px currentColor' }}>
               {lastHit?.label}
             </div>
             {lastHit && lastHit.score > 0 && (
                 <div className="text-xl font-orbitron text-white mt-2 tracking-widest">
                     +{lastHit.score}
                 </div>
             )}
          </div>

          {/* Combo Counter (Floating) */}
          {stats.combo > 5 && (
              <div className="absolute bottom-1/4 z-10 animate-bounce">
                  <div className={`text-5xl font-orbitron font-black text-${selectedLevel.color}-500 opacity-50`}>
                      {stats.combo} COMBO
                  </div>
              </div>
          )}

          {/* Bottom Prompt */}
          <div className="absolute bottom-12 w-full text-center z-10 opacity-50">
             <span className="text-[10px] font-orbitron text-white tracking-[1em] uppercase">Press Space to Rhythm</span>
          </div>
        </>
      )}

      {/* --- RESULTS STATE --- */}
      {gameState === GameState.RESULTS && (
        <div className="z-20 w-full max-w-2xl bg-zinc-950/90 backdrop-blur-2xl border border-white/10 p-12 rounded-3xl shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-500">
          <div className="flex justify-between items-center mb-12 border-b border-white/10 pb-8">
            <h2 className="text-4xl font-orbitron font-black text-white tracking-tight">SESSION REPORT</h2>
            <div className={`px-4 py-2 bg-${selectedLevel?.color || 'cyan'}-900/30 rounded border border-${selectedLevel?.color || 'cyan'}-500/30 text-${selectedLevel?.color || 'cyan'}-300 font-orbitron text-sm`}>
                {selectedLevel?.name}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-12 mb-12 font-orbitron">
             <div className="flex flex-col justify-center space-y-6">
                 <StatRow label="PERFECT" count={stats.perfects} total={stats.totalScore} color="text-white" />
                 <StatRow label="GREAT" count={stats.greats} total={stats.totalScore} color={`text-${selectedLevel?.color}-300`} />
                 <StatRow label="GOOD" count={stats.goods} total={stats.totalScore} color="text-yellow-500" />
                 <StatRow label="MISS" count={stats.misses} total={stats.totalScore} color="text-red-500" />
             </div>

             <div className="flex flex-col justify-center items-center bg-white/5 rounded-2xl p-6">
                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Accuracy</div>
                 <div className="text-6xl font-bold text-white mb-6">{stats.averageAccuracy.toFixed(1)}%</div>

                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Max Combo</div>
                 <div className={`text-4xl font-bold text-${selectedLevel?.color}-400`}>{stats.maxCombo}</div>
             </div>
          </div>

          {/* AI Commentary */}
          <div className="p-6 bg-gradient-to-r from-zinc-900 to-black rounded-xl mb-8 border-l-4 border-white/20">
            <div className="text-[10px] font-orbitron text-zinc-500 uppercase tracking-widest mb-2">System Analysis</div>
            <div className="text-lg font-light italic text-zinc-300 min-h-[1.5em]">
                {loadingAI ? "Analyzing rhythm patterns..." : `"${aiComment}"`}
            </div>
          </div>

          <div className="flex space-x-4">
             <button 
                onClick={() => setGameState(GameState.IDLE)}
                className="flex-1 py-4 border border-white/20 text-white font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-white/10 transition-colors rounded"
              >
                Select Level
              </button>
              <button 
                onClick={() => selectedLevel && startGame(selectedLevel)}
                className={`flex-1 py-4 bg-${selectedLevel?.color || 'cyan'}-500 text-black font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-${selectedLevel?.color || 'cyan'}-400 transition-colors rounded shadow-[0_0_20px_rgba(34,211,238,0.3)]`}
              >
                Retry
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

