import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level, Difficulty, GameConfig } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds

// Scoring Windows (ms) for [Perfect+, Perfect, Great, Good]
const SCORING_WINDOWS = {
  [Difficulty.EASY]:   [40, 70, 130, 200],
  [Difficulty.MEDIUM]: [25, 50, 100, 150],
  [Difficulty.HARD]:   [15, 30, 60, 100]
};

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [gameConfig, setGameConfig] = useState<GameConfig | null>(null);

  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const noiseBuffer = useRef<AudioBuffer | null>(null); // For Hi-Hats

  const nextNoteTime = useRef<number>(0.0); // For the Rhythm Pattern
  const nextMetronomeTime = useRef<number>(0.0); // For the steady Kick

  const currentBeatInPattern = useRef<number>(0);
  const timerID = useRef<number | null>(null);
  const loopStartTime = useRef<number>(0);

  // Queue for scoring
  const expectedHits = useRef<Array<{ time: number, processed: boolean }>>([]);

  // Visualizer Refs (Triggered on Metronome beats)
  const [beatTrigger, setBeatTrigger] = useState(0);

  // Initialize Audio Context and Noise Buffer
  const initAudio = async () => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    // Generate White Noise Buffer for Hi-Hats if not exists
    if (!noiseBuffer.current) {
      const bufferSize = audioContext.current.sampleRate * 2.0; // 2 seconds
      const buffer = audioContext.current.createBuffer(1, bufferSize, audioContext.current.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
      }
      noiseBuffer.current = buffer;
    }
  };

  const playKick = useCallback((time: number) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(50, time + 0.1);

    gain.gain.setValueAtTime(0.8, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const playHiHat = useCallback((time: number) => {
    if (!audioContext.current || !noiseBuffer.current) return;
    const ctx = audioContext.current;

    const source = ctx.createBufferSource();
    source.buffer = noiseBuffer.current;

    // Bandpass filter to shape the noise
    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 7000;

    const gain = ctx.createGain();
    // Sharp attack, fast decay
    gain.gain.setValueAtTime(0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    source.start(time);
    source.stop(time + 0.1);
  }, []);

  // Schedule the Rhythm Pattern (Target)
  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    // Add to scoring queue
    expectedHits.current.push({ time: time, processed: false });

    // Clean up old expected hits
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);

    // Play Hi-Hat (The Target Sound)
    playHiHat(time);
  }, [playHiHat]);

  // Main Scheduler Loop
  const scheduler = useCallback(() => {
    if (!gameConfig || !audioContext.current || gameState !== GameState.PLAYING) return;

    // IMPORTANT: If context is suspended (paused), currentTime doesn't advance.
    // However, we double check here to prevent scheduling pile-ups.
    if (audioContext.current.state === 'suspended') return;

    const beatDuration = 60 / gameConfig.bpm;

    // 1. Schedule Metronome
    while (nextMetronomeTime.current < audioContext.current.currentTime + SCHEDULE_AHEAD_TIME) {
        playKick(nextMetronomeTime.current);

        const timeToNote = (nextMetronomeTime.current - audioContext.current.currentTime) * 1000;
        setTimeout(() => {
            if (gameState === GameState.PLAYING) setBeatTrigger(prev => prev + 1);
        }, Math.max(0, timeToNote));

        nextMetronomeTime.current += beatDuration;
    }

    // 2. Schedule Rhythm Pattern
    while (nextNoteTime.current < audioContext.current.currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);

        const pattern = gameConfig.level.pattern;
        const currentBeatVal = pattern[currentBeatInPattern.current];

        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];

        let beatDiff = 0;
        if (nextIndex === 0) {
            beatDiff = gameConfig.level.loopBeats - currentBeatVal + nextBeatVal;
        } else {
            beatDiff = nextBeatVal - currentBeatVal;
        }

        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }

    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [gameConfig, gameState, scheduleNote, playKick]);

  // Handle Scheduler Lifecycle
  useEffect(() => {
      if (gameState === GameState.PLAYING && gameConfig && audioContext.current) {
          if (audioContext.current.state === 'suspended') {
              audioContext.current.resume();
          }
          scheduler();
      } else if (gameState === GameState.PAUSED && audioContext.current) {
          audioContext.current.suspend();
          if (timerID.current) window.clearTimeout(timerID.current);
      }

      return () => {
          if (timerID.current) window.clearTimeout(timerID.current);
      };
  }, [gameState, gameConfig, scheduler]);


  const selectLevel = (config: GameConfig) => {
      setGameConfig(config);
      startGame(config);
  };

  const startGame = async (config: GameConfig) => {
    await initAudio();

    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0,
      combo: 0,
      maxCombo: 0,
      perfects: 0,
      greats: 0,
      goods: 0,
      misses: 0,
      averageAccuracy: 0
    });
    setAiComment("");
    setLastHit(null);
    expectedHits.current = [];

    setTimeout(() => {
      if (audioContext.current) {
          const now = audioContext.current.currentTime;
          const startTime = now + 0.1;
          const beatDuration = 60 / config.bpm;

          nextMetronomeTime.current = startTime; 
          nextNoteTime.current = startTime + (config.level.pattern[0] * beatDuration); 
          loopStartTime.current = startTime;
          currentBeatInPattern.current = 0;
      }

      setGameState(GameState.PLAYING);
    }, 1500);
  };

  const togglePause = useCallback(() => {
      if (gameState === GameState.PLAYING) {
          setGameState(GameState.PAUSED);
      } else if (gameState === GameState.PAUSED) {
          setGameState(GameState.PLAYING);
      }
  }, [gameState]);

  const quitGame = () => {
      if (audioContext.current) {
          audioContext.current.suspend();
      }
      setGameState(GameState.IDLE);
      setGameConfig(null);
  };

  // Keyboard controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        handleTap();
      } else if (e.code === 'Escape') {
          if (gameState === GameState.PLAYING || gameState === GameState.PAUSED) {
              togglePause();
          }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap, togglePause, gameState]); // Added dependencies to ensure latest state is used

  // End Game (Finish Line)
  useEffect(() => {
      if (gameState === GameState.RESULTS) {
          endGame();
      }
  }, [gameState]);

  const endGame = useCallback(async () => {
    setLoadingAI(true);
    setStats(prev => {
        getAICommentary({
            perfects: prev.perfects,
            misses: prev.misses,
            averageAccuracy: prev.averageAccuracy
        }).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });
        return prev;
    });
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current || !gameConfig) return;

    const tapTime = audioContext.current.currentTime;

    // Scoring Logic
    const activeHits = expectedHits.current.filter(h => !h.processed);

    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) {
            minDiff = diff;
            closestHit = hit;
        }
    }

    const diffMs = minDiff * 1000;

    let score = 0;
    let label = "MISS";
    let color = "text-red-500";

    const windows = SCORING_WINDOWS[gameConfig.difficulty];

    if (closestHit && diffMs < windows[3]) { // Max Window (Good)
        closestHit.processed = true;

        if (diffMs < windows[0]) { // Perfect+
             score = 100;
             label = "PERFECT+";
             color = `text-white drop-shadow-[0_0_10px_white]`;
        } else if (diffMs < windows[1]) { // Perfect
             score = 90 + Math.floor((windows[1] - diffMs)/(windows[1]-windows[0]) * 10);
             label = "PERFECT";
             color = `text-${gameConfig.level.color}-300`;
        } else if (diffMs < windows[2]) { // Great
             score = 70 + Math.floor((windows[2] - diffMs)/(windows[2]-windows[1]) * 20);
             label = "GREAT";
             color = `text-${gameConfig.level.color}-400`;
        } else { // Good
             score = 40 + Math.floor((windows[3] - diffMs)/(windows[3]-windows[2]) * 30);
             label = "GOOD";
             color = "text-yellow-400";
        }
    } else {
        score = 0;
        label = "MISS";
        color = "text-red-600";
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;

      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, gameConfig]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden">

      {/* Background Visualizer Layer */}
      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={gameConfig.level}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {/* --- IDLE STATE: LEVEL SELECTOR --- */}
      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {/* --- STARTING STATE --- */}
      {gameState === GameState.STARTING && gameConfig && (
        <div className="z-10 text-center">
           <div className={`text-2xl font-orbitron text-${gameConfig.level.color}-400 mb-4 tracking-widest uppercase`}>Syncing Neural Link...</div>
           <div className="text-9xl font-orbitron font-black text-white animate-pulse">
            GET READY
          </div>
        </div>
      )}

      {/* --- PLAYING / PAUSED HUD --- */}
      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <>
          {/* Top HUD */}
          <div className="absolute top-0 left-0 w-full p-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className={`px-3 py-1 bg-${gameConfig.level.color}-500/20 border border-${gameConfig.level.color}-500/50 rounded text-xs font-orbitron text-${gameConfig.level.color}-300 tracking-widest mb-2 flex items-center gap-2`}>
                     <span>{gameConfig.level.name.toUpperCase()}</span>
                     <span className="w-1 h-1 bg-white rounded-full opacity-50"></span>
                     <span>{gameConfig.difficulty}</span>
                     <span className="w-1 h-1 bg-white rounded-full opacity-50"></span>
                     <span>{gameConfig.bpm} BPM</span>
                 </div>
                 <div className="text-4xl font-orbitron font-bold text-white tracking-tighter">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className="text-xs font-orbitron text-zinc-400 tracking-widest mb-1">ACCURACY</div>
                 <div className={`text-4xl font-orbitron font-bold ${stats.averageAccuracy > 90 ? 'text-white' : `text-${gameConfig.level.color}-400`}`}>
                     {stats.averageAccuracy.toFixed(1)}%
                 </div>
             </div>
          </div>

          {/* Center Hit Feedback (Hide if paused) */}
          {gameState === GameState.PLAYING && (
            <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
                <div className={`text-6xl font-orbitron font-black transition-all duration-75 transform ${lastHit ? 'scale-110 opacity-100 translate-y-0' : 'scale-90 opacity-0 translate-y-4'} ${lastHit?.color}`} style={{ textShadow: '0 0 30px currentColor' }}>
                {lastHit?.label}
                </div>
                {lastHit && lastHit.score > 0 && (
                    <div className="text-xl font-orbitron text-white mt-2 tracking-widest">
                        +{lastHit.score}
                    </div>
                )}
            </div>
          )}

          {/* Pause Overlay */}
          {gameState === GameState.PAUSED && (
            <div className="absolute inset-0 z-50 bg-black/80 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-200">
                <h2 className="text-6xl font-orbitron font-black text-white tracking-[0.2em] mb-12">SYSTEM PAUSED</h2>
                <div className="flex flex-col space-y-4 w-64">
                    <button onClick={togglePause} className={`py-4 bg-${gameConfig.level.color}-500 hover:bg-${gameConfig.level.color}-400 text-black font-bold font-orbitron uppercase tracking-widest rounded`}>
                        Resume
                    </button>
                    <button onClick={quitGame} className="py-4 border border-zinc-700 hover:bg-zinc-800 text-zinc-400 hover:text-white font-bold font-orbitron uppercase tracking-widest rounded transition-colors">
                        Abort Mission
                    </button>
                </div>
            </div>
          )}

          {/* Combo Counter (Floating) */}
          {stats.combo > 5 && gameState === GameState.PLAYING && (
              <div className="absolute bottom-1/4 z-10 animate-bounce">
                  <div className={`text-5xl font-orbitron font-black text-${gameConfig.level.color}-500 opacity-50`}>
                      {stats.combo} COMBO
                  </div>
              </div>
          )}

          {/* Bottom Prompt */}
          <div className="absolute bottom-12 w-full text-center z-10 opacity-50">
             <span className="text-[10px] font-orbitron text-white tracking-[1em] uppercase">Press ESC to Pause</span>
          </div>
        </>
      )}

      {/* --- RESULTS STATE --- */}
      {gameState === GameState.RESULTS && gameConfig && (
        <div className="z-20 w-full max-w-2xl bg-zinc-950/90 backdrop-blur-2xl border border-white/10 p-12 rounded-3xl shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-500">
          <div className="flex justify-between items-center mb-12 border-b border-white/10 pb-8">
            <h2 className="text-4xl font-orbitron font-black text-white tracking-tight">SESSION REPORT</h2>
            <div className={`px-4 py-2 bg-${gameConfig.level.color}-900/30 rounded border border-${gameConfig.level.color}-500/30 text-${gameConfig.level.color}-300 font-orbitron text-sm`}>
                {gameConfig.level.name}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-12 mb-12 font-orbitron">
             <div className="flex flex-col justify-center space-y-6">
                 <StatRow label="PERFECT" count={stats.perfects} total={stats.totalScore} color="text-white" />
                 <StatRow label="GREAT" count={stats.greats} total={stats.totalScore} color={`text-${gameConfig.level.color}-300`} />
                 <StatRow label="GOOD" count={stats.goods} total={stats.totalScore} color="text-yellow-500" />
                 <StatRow label="MISS" count={stats.misses} total={stats.totalScore} color="text-red-500" />
             </div>

             <div className="flex flex-col justify-center items-center bg-white/5 rounded-2xl p-6">
                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Accuracy</div>
                 <div className="text-6xl font-bold text-white mb-6">{stats.averageAccuracy.toFixed(1)}%</div>

                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Max Combo</div>
                 <div className={`text-4xl font-bold text-${gameConfig.level.color}-400`}>{stats.maxCombo}</div>
             </div>
          </div>

          {/* AI Commentary */}
          <div className="p-6 bg-gradient-to-r from-zinc-900 to-black rounded-xl mb-8 border-l-4 border-white/20">
            <div className="text-[10px] font-orbitron text-zinc-500 uppercase tracking-widest mb-2">System Analysis</div>
            <div className="text-lg font-light italic text-zinc-300 min-h-[1.5em]">
                {loadingAI ? "Analyzing rhythm patterns..." : `"${aiComment}"`}
            </div>
          </div>

          <div className="flex space-x-4">
             <button 
                onClick={quitGame}
                className="flex-1 py-4 border border-white/20 text-white font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-white/10 transition-colors rounded"
              >
                Level Select
              </button>
              <button 
                onClick={() => startGame(gameConfig)}
                className={`flex-1 py-4 bg-${gameConfig.level.color}-500 text-black font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-${gameConfig.level.color}-400 transition-colors rounded shadow-[0_0_20px_rgba(34,211,238,0.3)]`}
              >
                Retry
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

const StatRow = ({ label, count, total, color }: { label: string, count: number, total: number, color: string }) => (
    <div className="flex justify-between items-center group">
        <span className="text-zinc-500 text-sm font-bold tracking-widest group-hover:text-white transition-colors">{label}</span>
        <span className={`text-2xl font-bold ${color}`}>{count}</span>
    </div>
);

export default RhythmEngine;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level, Difficulty, GameConfig } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds

// Scoring Windows (ms) for [Perfect+, Perfect, Great, Good]
const SCORING_WINDOWS = {
  [Difficulty.EASY]:   [40, 70, 130, 200],
  [Difficulty.MEDIUM]: [25, 50, 100, 150],
  [Difficulty.HARD]:   [15, 30, 60, 100]
};

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [gameConfig, setGameConfig] = useState<GameConfig | null>(null);

  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const noiseBuffer = useRef<AudioBuffer | null>(null); // For Hi-Hats

  const nextNoteTime = useRef<number>(0.0); // For the Rhythm Pattern
  const nextMetronomeTime = useRef<number>(0.0); // For the steady Kick

  const currentBeatInPattern = useRef<number>(0);
  const timerID = useRef<number | null>(null);
  const loopStartTime = useRef<number>(0);

  // Queue for scoring
  const expectedHits = useRef<Array<{ time: number, processed: boolean }>>([]);

  // Visualizer Refs (Triggered on Metronome beats)
  const [beatTrigger, setBeatTrigger] = useState(0);

  // Initialize Audio Context and Noise Buffer
  const initAudio = async () => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    // Generate White Noise Buffer for Hi-Hats if not exists
    if (!noiseBuffer.current) {
      const bufferSize = audioContext.current.sampleRate * 2.0; // 2 seconds
      const buffer = audioContext.current.createBuffer(1, bufferSize, audioContext.current.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
      }
      noiseBuffer.current = buffer;
    }
  };

  const playKick = useCallback((time: number) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(50, time + 0.1);

    gain.gain.setValueAtTime(0.8, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const playHiHat = useCallback((time: number) => {
    if (!audioContext.current || !noiseBuffer.current) return;
    const ctx = audioContext.current;

    const source = ctx.createBufferSource();
    source.buffer = noiseBuffer.current;

    // Bandpass filter to shape the noise
    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 7000;

    const gain = ctx.createGain();
    // Sharp attack, fast decay
    gain.gain.setValueAtTime(0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    source.start(time);
    source.stop(time + 0.1);
  }, []);

  // Schedule the Rhythm Pattern (Target)
  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    // Add to scoring queue
    expectedHits.current.push({ time: time, processed: false });

    // Clean up old expected hits
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);

    // Play Hi-Hat (The Target Sound)
    playHiHat(time);
  }, [playHiHat]);

  // Main Scheduler Loop
  const scheduler = useCallback(() => {
    if (!gameConfig || !audioContext.current || gameState !== GameState.PLAYING) return;

    // IMPORTANT: If context is suspended (paused), currentTime doesn't advance.
    // However, we double check here to prevent scheduling pile-ups.
    if (audioContext.current.state === 'suspended') return;

    const beatDuration = 60 / gameConfig.bpm;

    // 1. Schedule Metronome
    while (nextMetronomeTime.current < audioContext.current.currentTime + SCHEDULE_AHEAD_TIME) {
        playKick(nextMetronomeTime.current);

        const timeToNote = (nextMetronomeTime.current - audioContext.current.currentTime) * 1000;
        setTimeout(() => {
            if (gameState === GameState.PLAYING) setBeatTrigger(prev => prev + 1);
        }, Math.max(0, timeToNote));

        nextMetronomeTime.current += beatDuration;
    }

    // 2. Schedule Rhythm Pattern
    while (nextNoteTime.current < audioContext.current.currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);

        const pattern = gameConfig.level.pattern;
        const currentBeatVal = pattern[currentBeatInPattern.current];

        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];

        let beatDiff = 0;
        if (nextIndex === 0) {
            beatDiff = gameConfig.level.loopBeats - currentBeatVal + nextBeatVal;
        } else {
            beatDiff = nextBeatVal - currentBeatVal;
        }

        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }

    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [gameConfig, gameState, scheduleNote, playKick]);

  // Handle Scheduler Lifecycle
  useEffect(() => {
      if (gameState === GameState.PLAYING && gameConfig && audioContext.current) {
          if (audioContext.current.state === 'suspended') {
              audioContext.current.resume();
          }
          scheduler();
      } else if (gameState === GameState.PAUSED && audioContext.current) {
          audioContext.current.suspend();
          if (timerID.current) window.clearTimeout(timerID.current);
      }

      return () => {
          if (timerID.current) window.clearTimeout(timerID.current);
      };
  }, [gameState, gameConfig, scheduler]);


  const selectLevel = (config: GameConfig) => {
      setGameConfig(config);
      startGame(config);
  };

  const startGame = async (config: GameConfig) => {
    await initAudio();

    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0,
      combo: 0,
      maxCombo: 0,
      perfects: 0,
      greats: 0,
      goods: 0,
      misses: 0,
      averageAccuracy: 0
    });
    setAiComment("");
    setLastHit(null);
    expectedHits.current = [];

    setTimeout(() => {
      if (audioContext.current) {
          const now = audioContext.current.currentTime;
          const startTime = now + 0.1;
          const beatDuration = 60 / config.bpm;

          nextMetronomeTime.current = startTime; 
          nextNoteTime.current = startTime + (config.level.pattern[0] * beatDuration); 
          loopStartTime.current = startTime;
          currentBeatInPattern.current = 0;
      }

      setGameState(GameState.PLAYING);
    }, 1500);
  };

  const togglePause = useCallback(() => {
      if (gameState === GameState.PLAYING) {
          setGameState(GameState.PAUSED);
      } else if (gameState === GameState.PAUSED) {
          setGameState(GameState.PLAYING);
      }
  }, [gameState]);

  const quitGame = () => {
      if (audioContext.current) {
          audioContext.current.suspend();
      }
      setGameState(GameState.IDLE);
      setGameConfig(null);
  };

  const endGame = useCallback(async () => {
    setLoadingAI(true);
    setStats(prev => {
        getAICommentary({
            perfects: prev.perfects,
            misses: prev.misses,
            averageAccuracy: prev.averageAccuracy
        }).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });
        return prev;
    });
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current || !gameConfig) return;

    const tapTime = audioContext.current.currentTime;

    // Scoring Logic
    const activeHits = expectedHits.current.filter(h => !h.processed);

    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) {
            minDiff = diff;
            closestHit = hit;
        }
    }

    const diffMs = minDiff * 1000;

    let score = 0;
    let label = "MISS";
    let color = "text-red-500";

    const windows = SCORING_WINDOWS[gameConfig.difficulty];

    if (closestHit && diffMs < windows[3]) { // Max Window (Good)
        closestHit.processed = true;

        if (diffMs < windows[0]) { // Perfect+
             score = 100;
             label = "PERFECT+";
             color = `text-white drop-shadow-[0_0_10px_white]`;
        } else if (diffMs < windows[1]) { // Perfect
             score = 90 + Math.floor((windows[1] - diffMs)/(windows[1]-windows[0]) * 10);
             label = "PERFECT";
             color = `text-${gameConfig.level.color}-300`;
        } else if (diffMs < windows[2]) { // Great
             score = 70 + Math.floor((windows[2] - diffMs)/(windows[2]-windows[1]) * 20);
             label = "GREAT";
             color = `text-${gameConfig.level.color}-400`;
        } else { // Good
             score = 40 + Math.floor((windows[3] - diffMs)/(windows[3]-windows[2]) * 30);
             label = "GOOD";
             color = "text-yellow-400";
        }
    } else {
        score = 0;
        label = "MISS";
        color = "text-red-600";
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;

      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, gameConfig]);

  // Keyboard controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        handleTap();
      } else if (e.code === 'Escape') {
          if (gameState === GameState.PLAYING || gameState === GameState.PAUSED) {
              togglePause();
          }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap, togglePause, gameState]); // Added dependencies to ensure latest state is used

  // End Game (Finish Line)
  useEffect(() => {
      if (gameState === GameState.RESULTS) {
          endGame();
      }
  }, [gameState, endGame]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden">

      {/* Background Visualizer Layer */}
      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={gameConfig.level}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {/* --- IDLE STATE: LEVEL SELECTOR --- */}
      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {/* --- STARTING STATE --- */}
      {gameState === GameState.STARTING && gameConfig && (
        <div className="z-10 text-center">
           <div className={`text-2xl font-orbitron text-${gameConfig.level.color}-400 mb-4 tracking-widest uppercase`}>Syncing Neural Link...</div>
           <div className="text-9xl font-orbitron font-black text-white animate-pulse">
            GET READY
          </div>
        </div>
      )}

      {/* --- PLAYING / PAUSED HUD --- */}
      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <>
          {/* Top HUD */}
          <div className="absolute top-0 left-0 w-full p-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className={`px-3 py-1 bg-${gameConfig.level.color}-500/20 border border-${gameConfig.level.color}-500/50 rounded text-xs font-orbitron text-${gameConfig.level.color}-300 tracking-widest mb-2 flex items-center gap-2`}>
                     <span>{gameConfig.level.name.toUpperCase()}</span>
                     <span className="w-1 h-1 bg-white rounded-full opacity-50"></span>
                     <span>{gameConfig.difficulty}</span>
                     <span className="w-1 h-1 bg-white rounded-full opacity-50"></span>
                     <span>{gameConfig.bpm} BPM</span>
                 </div>
                 <div className="text-4xl font-orbitron font-bold text-white tracking-tighter">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className="text-xs font-orbitron text-zinc-400 tracking-widest mb-1">ACCURACY</div>
                 <div className={`text-4xl font-orbitron font-bold ${stats.averageAccuracy > 90 ? 'text-white' : `text-${gameConfig.level.color}-400`}`}>
                     {stats.averageAccuracy.toFixed(1)}%
                 </div>
             </div>
          </div>

          {/* Center Hit Feedback (Hide if paused) */}
          {gameState === GameState.PLAYING && (
            <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
                <div className={`text-6xl font-orbitron font-black transition-all duration-75 transform ${lastHit ? 'scale-110 opacity-100 translate-y-0' : 'scale-90 opacity-0 translate-y-4'} ${lastHit?.color}`} style={{ textShadow: '0 0 30px currentColor' }}>
                {lastHit?.label}
                </div>
                {lastHit && lastHit.score > 0 && (
                    <div className="text-xl font-orbitron text-white mt-2 tracking-widest">
                        +{lastHit.score}
                    </div>
                )}
            </div>
          )}

          {/* Pause Overlay */}
          {gameState === GameState.PAUSED && (
            <div className="absolute inset-0 z-50 bg-black/80 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-200">
                <h2 className="text-6xl font-orbitron font-black text-white tracking-[0.2em] mb-12">SYSTEM PAUSED</h2>
                <div className="flex flex-col space-y-4 w-64">
                    <button onClick={togglePause} className={`py-4 bg-${gameConfig.level.color}-500 hover:bg-${gameConfig.level.color}-400 text-black font-bold font-orbitron uppercase tracking-widest rounded`}>
                        Resume
                    </button>
                    <button onClick={quitGame} className="py-4 border border-zinc-700 hover:bg-zinc-800 text-zinc-400 hover:text-white font-bold font-orbitron uppercase tracking-widest rounded transition-colors">
                        Abort Mission
                    </button>
                </div>
            </div>
          )}

          {/* Combo Counter (Floating) */}
          {stats.combo > 5 && gameState === GameState.PLAYING && (
              <div className="absolute bottom-1/4 z-10 animate-bounce">
                  <div className={`text-5xl font-orbitron font-black text-${gameConfig.level.color}-500 opacity-50`}>
                      {stats.combo} COMBO
                  </div>
              </div>
          )}

          {/* Bottom Prompt */}
          <div className="absolute bottom-12 w-full text-center z-10 opacity-50">
             <span className="text-[10px] font-orbitron text-white tracking-[1em] uppercase">Press ESC to Pause</span>
          </div>
        </>
      )}

      {/* --- RESULTS STATE --- */}
      {gameState === GameState.RESULTS && gameConfig && (
        <div className="z-20 w-full max-w-2xl bg-zinc-950/90 backdrop-blur-2xl border border-white/10 p-12 rounded-3xl shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-500">
          <div className="flex justify-between items-center mb-12 border-b border-white/10 pb-8">
            <h2 className="text-4xl font-orbitron font-black text-white tracking-tight">SESSION REPORT</h2>
            <div className={`px-4 py-2 bg-${gameConfig.level.color}-900/30 rounded border border-${gameConfig.level.color}-500/30 text-${gameConfig.level.color}-300 font-orbitron text-sm`}>
                {gameConfig.level.name}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-12 mb-12 font-orbitron">
             <div className="flex flex-col justify-center space-y-6">
                 <StatRow label="PERFECT" count={stats.perfects} total={stats.totalScore} color="text-white" />
                 <StatRow label="GREAT" count={stats.greats} total={stats.totalScore} color={`text-${gameConfig.level.color}-300`} />
                 <StatRow label="GOOD" count={stats.goods} total={stats.totalScore} color="text-yellow-500" />
                 <StatRow label="MISS" count={stats.misses} total={stats.totalScore} color="text-red-500" />
             </div>

             <div className="flex flex-col justify-center items-center bg-white/5 rounded-2xl p-6">
                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Accuracy</div>
                 <div className="text-6xl font-bold text-white mb-6">{stats.averageAccuracy.toFixed(1)}%</div>

                 <div className="text-zinc-500 text-xs tracking-widest uppercase mb-2">Max Combo</div>
                 <div className={`text-4xl font-bold text-${gameConfig.level.color}-400`}>{stats.maxCombo}</div>
             </div>
          </div>

          {/* AI Commentary */}
          <div className="p-6 bg-gradient-to-r from-zinc-900 to-black rounded-xl mb-8 border-l-4 border-white/20">
            <div className="text-[10px] font-orbitron text-zinc-500 uppercase tracking-widest mb-2">System Analysis</div>
            <div className="text-lg font-light italic text-zinc-300 min-h-[1.5em]">
                {loadingAI ? "Analyzing rhythm patterns..." : `"${aiComment}"`}
            </div>
          </div>

          <div className="flex space-x-4">
             <button 
                onClick={quitGame}
                className="flex-1 py-4 border border-white/20 text-white font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-white/10 transition-colors rounded"
              >
                Level Select
              </button>
              <button 
                onClick={() => startGame(gameConfig)}
                className={`flex-1 py-4 bg-${gameConfig.level.color}-500 text-black font-orbitron font-bold text-sm uppercase tracking-widest hover:bg-${gameConfig.level.color}-400 transition-colors rounded shadow-[0_0_20px_rgba(34,211,238,0.3)]`}
              >
                Retry
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

const StatRow = ({ label, count, total, color }: { label: string, count: number, total: number, color: string }) => (
    <div className="flex justify-between items-center group">
        <span className="text-zinc-500 text-sm font-bold tracking-widest group-hover:text-white transition-colors">{label}</span>
        <span className={`text-2xl font-bold ${color}`}>{count}</span>
    </div>
);

export default RhythmEngine;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level, Difficulty, GameConfig } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds

// Scoring Windows (ms) for [Perfect+, Perfect, Great, Good]
const SCORING_WINDOWS = {
  [Difficulty.EASY]:   [40, 70, 130, 200],
  [Difficulty.MEDIUM]: [25, 50, 100, 150],
  [Difficulty.HARD]:   [15, 30, 60, 100]
};

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [gameConfig, setGameConfig] = useState<GameConfig | null>(null);

  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const noiseBuffer = useRef<AudioBuffer | null>(null); // For Hi-Hats

  const nextNoteTime = useRef<number>(0.0); // For the Rhythm Pattern
  const nextMetronomeTime = useRef<number>(0.0); // For the steady Kick

  const currentBeatInPattern = useRef<number>(0);
  const timerID = useRef<number | null>(null);
  const loopStartTime = useRef<number>(0);

  // Queue for scoring
  const expectedHits = useRef<Array<{ time: number, processed: boolean }>>([]);

  // Visualizer Refs (Triggered on Metronome beats)
  const [beatTrigger, setBeatTrigger] = useState(0);

  // Initialize Audio Context and Noise Buffer
  const initAudio = async () => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    // Generate White Noise Buffer for Hi-Hats if not exists
    if (!noiseBuffer.current) {
      const bufferSize = audioContext.current.sampleRate * 2.0; // 2 seconds
      const buffer = audioContext.current.createBuffer(1, bufferSize, audioContext.current.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
      }
      noiseBuffer.current = buffer;
    }
  };

  const playKick = useCallback((time: number) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(50, time + 0.1);

    gain.gain.setValueAtTime(0.8, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const playHiHat = useCallback((time: number) => {
    if (!audioContext.current || !noiseBuffer.current) return;
    const ctx = audioContext.current;

    const source = ctx.createBufferSource();
    source.buffer = noiseBuffer.current;

    // Bandpass filter to shape the noise
    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 7000;

    const gain = ctx.createGain();
    // Sharp attack, fast decay
    gain.gain.setValueAtTime(0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    source.start(time);
    source.stop(time + 0.1);
  }, []);

  // Schedule the Rhythm Pattern (Target)
  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    // Add to scoring queue
    expectedHits.current.push({ time: time, processed: false });

    // Clean up old expected hits
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);

    // Play Hi-Hat (The Target Sound)
    playHiHat(time);
  }, [playHiHat]);

  // Main Scheduler Loop
  const scheduler = useCallback(() => {
    if (!gameConfig || !audioContext.current || gameState !== GameState.PLAYING) return;

    // IMPORTANT: If context is suspended (paused), currentTime doesn't advance.
    // However, we double check here to prevent scheduling pile-ups.
    if (audioContext.current.state === 'suspended') return;

    const beatDuration = 60 / gameConfig.bpm;

    // 1. Schedule Metronome
    while (nextMetronomeTime.current < audioContext.current.currentTime + SCHEDULE_AHEAD_TIME) {
        playKick(nextMetronomeTime.current);

        const timeToNote = (nextMetronomeTime.current - audioContext.current.currentTime) * 1000;
        setTimeout(() => {
            if (gameState === GameState.PLAYING) setBeatTrigger(prev => prev + 1);
        }, Math.max(0, timeToNote));

        nextMetronomeTime.current += beatDuration;
    }

    // 2. Schedule Rhythm Pattern
    while (nextNoteTime.current < audioContext.current.currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);

        const pattern = gameConfig.level.pattern;
        const currentBeatVal = pattern[currentBeatInPattern.current];

        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];

        let beatDiff = 0;
        if (nextIndex === 0) {
            beatDiff = gameConfig.level.loopBeats - currentBeatVal + nextBeatVal;
        } else {
            beatDiff = nextBeatVal - currentBeatVal;
        }

        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }

    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [gameConfig, gameState, scheduleNote, playKick]);

  // Handle Scheduler Lifecycle
  useEffect(() => {
      let isActive = true; // Prevents running scheduler if component unmounts or state changes while waiting for resume

      if (gameState === GameState.PLAYING && gameConfig && audioContext.current) {
          if (audioContext.current.state === 'suspended') {
              audioContext.current.resume().then(() => {
                  if (isActive) scheduler();
              });
          } else {
              scheduler();
          }
      } else if (gameState === GameState.PAUSED && audioContext.current) {
          audioContext.current.suspend();
          if (timerID.current) window.clearTimeout(timerID.current);
      }

      return () => {
          isActive = false;
          if (timerID.current) window.clearTimeout(timerID.current);
      };
  }, [gameState, gameConfig, scheduler]);


  const selectLevel = (config: GameConfig) => {
      setGameConfig(config);
      startGame(config);
  };

  const startGame = async (config: GameConfig) => {
    await initAudio();

    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0,
      combo: 0,
      maxCombo: 0,
      perfects: 0,
      greats: 0,
      goods: 0,
      misses: 0,
      averageAccuracy: 0
    });
    setAiComment("");
    setLastHit(null);
    expectedHits.current = [];

    setTimeout(() => {
      if (audioContext.current) {
          const now = audioContext.current.currentTime;
          const startTime = now + 0.1;
          const beatDuration = 60 / config.bpm;

          nextMetronomeTime.current = startTime; 
          nextNoteTime.current = startTime + (config.level.pattern[0] * beatDuration); 
          loopStartTime.current = startTime;
          currentBeatInPattern.current = 0;
      }

      setGameState(GameState.PLAYING);
    }, 1500);
  };

  const togglePause = useCallback(() => {
      if (gameState === GameState.PLAYING) {
          setGameState(GameState.PAUSED);
      } else if (gameState === GameState.PAUSED) {
          setGameState(GameState.PLAYING);
      }
  }, [gameState]);

  const quitGame = useCallback(() => {
      if (audioContext.current) {
          audioContext.current.suspend();
      }
      setGameState(GameState.IDLE);
      setGameConfig(null);
  }, []);

  const endGame = useCallback(async () => {
    setLoadingAI(true);
    setStats(prev => {
        getAICommentary({
            perfects: prev.perfects,
            misses: prev.misses,
            averageAccuracy: prev.averageAccuracy
        }).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });
        return prev;
    });
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current || !gameConfig) return;

    const tapTime = audioContext.current.currentTime;

    // Scoring Logic
    const activeHits = expectedHits.current.filter(h => !h.processed);

    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) {
            minDiff = diff;
            closestHit = hit;
        }
    }

    const diffMs = minDiff * 1000;

    let score = 0;
    let label = "MISS";
    let color = "text-red-500";

    const windows = SCORING_WINDOWS[gameConfig.difficulty];

    if (closestHit && diffMs < windows[3]) { // Max Window (Good)
        closestHit.processed = true;

        if (diffMs < windows[0]) { // Perfect+
             score = 100;
             label = "PERFECT+";
             color = `text-white drop-shadow-[0_0_10px_white]`;
        } else if (diffMs < windows[1]) { // Perfect
             score = 90 + Math.floor((windows[1] - diffMs)/(windows[1]-windows[0]) * 10);
             label = "PERFECT";
             color = `text-${gameConfig.level.color}-300`;
        } else if (diffMs < windows[2]) { // Great
             score = 70 + Math.floor((windows[2] - diffMs)/(windows[2]-windows[1]) * 20);
             label = "GREAT";
             color = `text-${gameConfig.level.color}-400`;
        } else { // Good
             score = 40 + Math.floor((windows[3] - diffMs)/(windows[3]-windows[2]) * 30);
             label = "GOOD";
             color = "text-yellow-400";
        }
    } else {
        score = 0;
        label = "MISS";
        color = "text-red-600";
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;

      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, gameConfig]);

  // Keyboard controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        handleTap();
      } else if (e.code === 'Escape') {
          if (gameState === GameState.PLAYING || gameState === GameState.PAUSED) {
              togglePause();
          }
      } else if (e.code === 'KeyQ') {
          if (gameState === GameState.PAUSED) {
              quitGame();
          }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap, togglePause, gameState, quitGame]);

  // End Game (Finish Line)
  useEffect(() => {
      if (gameState === GameState.RESULTS) {
          endGame();
      }
  }, [gameState, endGame]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden">

      {/* Background Visualizer Layer */}
      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={gameConfig.level}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {/* --- IDLE STATE: LEVEL SELECTOR --- */}
      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {/* --- STARTING STATE --- */}
      {gameState === GameState.STARTING && gameConfig && (
        <div className="z-10 text-center">
           <div className={`text-2xl font-orbitron text-${gameConfig.level.color}-400 mb-4 tracking-widest uppercase`}>Syncing Neural Link...</div>
           <div className="text-9xl font-orbitron font-black text-white animate-pulse">
            GET READY
          </div>
        </div>
      )}

      {/* --- PLAYING / PAUSED HUD --- */}
      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <>
          {/* Top HUD */}
          <div className="absolute top-0 left-0 w-full p-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className={`px-3 py-1 bg-${gameConfig.level.color}-500/20 border border-${gameConfig.level.color}-500/50 rounded text-xs font-orbitron text-${gameConfig.level.color}-300 tracking-widest mb-2 flex items-center gap-2`}>
                     <span>{gameConfig.level.name.toUpperCase()}</span>
                     <span className="w-1 h-1 bg-white rounded-full opacity-50"></span>
                     <span>{gameConfig.difficulty}</span>
                     <span className="w-1 h-1 bg-white rounded-full opacity-50"></span>
                     <span>{gameConfig.bpm} BPM</span>
                 </div>
                 <div className="text-4xl font-orbitron font-bold text-white tracking-tighter">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className="text-xs font-orbitron text-zinc-400 tracking-widest mb-1">ACCURACY</div>
                 <div className={`text-4xl font-orbitron font-bold ${stats.averageAccuracy > 90 ? 'text-white' : `text-${gameConfig.level.color}-400`}`}>
                     {stats.averageAccuracy.toFixed(1)}%
                 </div>
             </div>
          </div>

          {/* Center Hit Feedback (Hide if paused) */}
          {gameState === GameState.PLAYING && (
            <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
                <div className={`text-6xl font-orbitron font-black transition-all duration-75 transform ${lastHit ? 'scale-110 opacity-100 translate-y-0' : 'scale-90 opacity-0 translate-y-4'} ${lastHit?.color}`} style={{ textShadow: '0 0 30px currentColor' }}>
                {lastHit?.label}
                </div>
                {lastHit && lastHit.score > 0 && (
                    <div className="text-xl font-orbitron text-white mt-2 tracking-widest">
                        +{lastHit.score}
                    </div>
                )}
            </div>
          )}

          {/* Pause Overlay */}
          {gameState === GameState.PAUSED && (
            <div className="absolute inset-0 z-50 bg-black/80 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-200">
                <h2 className="text-6xl font-orbitron font-black text-white tracking-[0.2em] mb-12">SYSTEM PAUSED</h2>
                <div className="flex flex-col space-y-4 w-64">
                    <button onClick={togglePause} className={`py-4 bg-${gameConfig.level.color}-500 hover:bg-${gameConfig.level.color}-400 text-black font-bold font-orbitron uppercase tracking-widest rounded`}>
                        Resume
                    </button>
                    <button onClick={quitGame} className="py-4 border border-zinc-700 hover:bg-zinc-800 text-zinc-400 hover:text-white font-bold font-orbitron uppercase tracking-widest rounded transition-colors">
                        Abort Mission <span className="text-xs text-zinc-600 ml-2">[Q]</span>
                    </button>
                </div>
            </div>
          )}

          {/* Combo Counter (Floating) */}
          {stats.combo > 5 && gameState === GameState.PLAYING && (
              <div className="absolute bottom-1/4 z-10 animate-bounce">
                  <div className={`text-5xl font-orbitron font-black text-${gameConfig.level.color}-500 opacity-50`}>
                      {stats.combo} COMBO
                  </div>
              </div>
          )}

          {/* Bottom Prompt */}
