import React, { useEffect, useRef } from 'react';
import { Level } from '../types';

interface VisualizerProps {
  isPlaying: boolean;
  level: Level;
  bpm: number; // Added BPM prop for sync
  audioContext: AudioContext | null;
  loopStartTime: number; // The timestamp of "Beat 0" to sync phase
  lastHitTime: number | null;
  hitScore: number | null;
  beatTrigger: number; // Still useful for pulse effects
}

const Visualizer: React.FC<VisualizerProps> = ({ 
  isPlaying, 
  level, 
  bpm,
  audioContext,
  loopStartTime,
  lastHitTime, 
  hitScore,
  beatTrigger 
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particles = useRef<Array<{ x: number, y: number, vx: number, vy: number, life: number, color: string, size: number }>>([]);
  const pulseRef = useRef(0);
  const lastBeatRef = useRef(beatTrigger);

  // Helper to convert beat position to angle (0 is top, clockwise)
  const getAngle = (beat: number, totalBeats: number) => {
    return (beat / totalBeats) * Math.PI * 2 - Math.PI / 2;
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;

    const render = () => {
      const w = canvas.width = window.innerWidth;
      const h = canvas.height = window.innerHeight;
      const cx = w / 2;
      const cy = h / 2;
      // Radius of the main rhythm circle
      const r = Math.min(w, h) * 0.35; 

      // Calculate Loop Progress internally for 60fps smoothness without React renders
      let loopProgress = 0;
      if (isPlaying && audioContext) {
          const now = audioContext.currentTime;
          const beatDuration = 60 / bpm; // Use the actual BPM
          const loopDuration = beatDuration * level.loopBeats;
          // Calculate phase-aligned progress
          // We add loopDuration to (now - start) before modulo to handle potential negative small numbers at start
          loopProgress = ((now - loopStartTime) % loopDuration) / loopDuration;
          if (loopProgress < 0) loopProgress += 1;
      } else {
          // Idle rotation
          loopProgress = (Date.now() % 5000) / 5000;
      }

      ctx.clearRect(0, 0, w, h);

      // Handle Pulse on Beat
      if (beatTrigger !== lastBeatRef.current) {
        pulseRef.current = 1.0;
        lastBeatRef.current = beatTrigger;
      }
      pulseRef.current = Math.max(0, pulseRef.current - 0.05);

      // --- Background & Atmosphere ---
      const bgGrad = ctx.createRadialGradient(cx, cy, r * 0.5, cx, cy, w);
      bgGrad.addColorStop(0, `${level.hex}11`);
      bgGrad.addColorStop(1, '#000000');
      ctx.fillStyle = bgGrad;
      ctx.fillRect(0, 0, w, h);

      if (isPlaying) {
        // --- The Rhythm Track (Circle) ---
        ctx.beginPath();
        ctx.arc(cx, cy, r, 0, Math.PI * 2);
        ctx.strokeStyle = '#333';
        ctx.lineWidth = 2;
        ctx.stroke();

        // Glow effect on track
        ctx.shadowBlur = 15;
        ctx.shadowColor = level.hex;
        ctx.beginPath();
        ctx.arc(cx, cy, r, 0, Math.PI * 2);
        ctx.strokeStyle = `${level.hex}33`; // Transparent level color
        ctx.lineWidth = 4 + pulseRef.current * 4;
        ctx.stroke();
        ctx.shadowBlur = 0;

        // --- Beat Markers (The Nodes) ---
        level.pattern.forEach(beat => {
          const angle = getAngle(beat, level.loopBeats);
          const x = cx + Math.cos(angle) * r;
          const y = cy + Math.sin(angle) * r;

          // Active Glow Check
          const nodeProgress = beat / level.loopBeats;
          let diff = Math.abs(loopProgress - nodeProgress);
          if (diff > 0.5) diff = 1 - diff; // Handle wrap-around

          // Flash when cursor passes
          const isActive = diff < 0.03; 

          ctx.beginPath();
          ctx.arc(x, y, isActive ? 12 : 6, 0, Math.PI * 2);
          ctx.fillStyle = isActive ? '#ffffff' : level.hex;
          ctx.fill();

          if (isActive) {
            ctx.shadowBlur = 20;
            ctx.shadowColor = '#ffffff';
            ctx.beginPath();
            ctx.arc(x, y, 20, 0, Math.PI * 2);
            ctx.fillStyle = `${level.hex}66`;
            ctx.fill();
            ctx.shadowBlur = 0;
          }
        });

        // --- The Cursor (Sweeping Radar) ---
        const cursorAngle = (loopProgress * Math.PI * 2) - Math.PI / 2;
        const cursorX = cx + Math.cos(cursorAngle) * r;
        const cursorY = cy + Math.sin(cursorAngle) * r;

        // Draw Line to cursor
        const grad = ctx.createLinearGradient(cx, cy, cursorX, cursorY);
        grad.addColorStop(0, 'transparent');
        grad.addColorStop(1, '#ffffff');
        ctx.beginPath();
        ctx.moveTo(cx, cy);
        ctx.lineTo(cursorX, cursorY);
        ctx.strokeStyle = grad;
        ctx.lineWidth = 2;
        ctx.stroke();

        // Draw Cursor Head
        ctx.beginPath();
        ctx.arc(cursorX, cursorY, 8, 0, Math.PI * 2);
        ctx.fillStyle = '#ffffff';
        ctx.fill();
      }

      // --- Particle System (Hits) ---
      particles.current = particles.current.filter(p => p.life > 0);
      particles.current.forEach(p => {
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI * 2);
        ctx.fill();
        p.x += p.vx;
        p.y += p.vy;
        p.life -= 0.03;
      });
      ctx.globalAlpha = 1.0;

      animationFrame = requestAnimationFrame(render);
    };

    animationFrame = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animationFrame);
  }, [isPlaying, level, bpm, loopStartTime, audioContext, beatTrigger]);

  // Handle particle spawns from prop changes
  useEffect(() => {
     if (hitScore !== null && hitScore !== undefined) {
         const w = canvasRef.current?.width || window.innerWidth;
         const h = canvasRef.current?.height || window.innerHeight;
         const cx = w/2;
         const cy = h/2;
         const count = Math.floor(hitScore / 5) + 5;
         const color = hitScore > 90 ? '#ffffff' : level.hex;

         for(let i=0; i<count; i++) {
             const angle = Math.random() * Math.PI * 2;
             const speed = Math.random() * 10 + 5;
             particles.current.push({
                 x: cx,
                 y: cy,
                 vx: Math.cos(angle) * speed,
                 vy: Math.sin(angle) * speed,
                 life: 1.0,
                 color: color,
                 size: Math.random() * 3 + 1
             });
         }
     }
  }, [lastHitTime, hitScore, level.hex]);

  return <canvas ref={canvasRef} className="absolute inset-0 z-0 pointer-events-none" />;
};

export default Visualizer;

