  return (
    <>
      <div className={`z-20 w-full max-w-6xl px-8 flex flex-col items-center animate-in fade-in zoom-in duration-500 ${selectedLevel ? 'blur-sm brightness-50 pointer-events-none' : ''} pb-12 overflow-y-auto max-h-screen py-12`}>
          <h1 className="text-6xl md:text-8xl font-orbitron font-black mb-4 bg-clip-text text-transparent bg-gradient-to-b from-white to-zinc-600 text-center">
