                      className="group relative h-[28rem] perspective-1000 transition-all duration-300 hover:-translate-y-2 focus:outline-none"
                  >
                      <div className={`absolute inset-0 bg-zinc-900/80 backdrop-blur-md border border-zinc-700 rounded-xl overflow-hidden transition-all duration-300 group-hover:border-${level.color}-400 group-hover:shadow-[0_0_30px_rgba(0,0,0,0.5)] flex flex-col`}>
                          {/* Level Header Color */}
                          <div className={`h-2 w-full bg-${level.color}-500 shadow-[0_0_15px_currentColor] shrink-0`}></div>

                          <div className="p-6 flex flex-col items-start text-left relative z-10 h-full w-full">
                              <div className={`text-xs font-bold text-${level.color}-400 mb-2 tracking-widest`}>BPM {level.bpm}</div>
                              <h3 className="text-2xl font-orbitron font-bold text-white mb-4 leading-tight group-hover:text-transparent group-hover:bg-clip-text group-hover:bg-gradient-to-r group-hover:from-white group-hover:to-zinc-400">
                                  {level.name}
                              </h3>
                              <p className="text-zinc-500 text-sm mb-6 font-light leading-relaxed h-12 overflow-hidden shrink-0">
                                  {level.description}
                              </p>

                              {/* High Scores Block */}
                              <div className="w-full bg-black/40 rounded p-3 mb-4 space-y-2 shrink-0">
                                <div className="text-[10px] text-zinc-500 uppercase tracking-wider text-center border-b border-zinc-800 pb-1">High Scores</div>
                                <div className="flex flex-col space-y-1">
                                    {[Difficulty.EASY, Difficulty.MEDIUM, Difficulty.HARD].map((diff) => (
                                        <div key={diff} className="flex justify-between items-center text-[10px] font-mono border-b border-zinc-800/50 pb-1 last:border-0 last:pb-0">
                                            <span className="text-zinc-500 w-8 text-left">{diff === Difficulty.MEDIUM ? 'MED' : diff}</span>
                                            <div className="text-right flex-1">{renderScore(level.id, diff)}</div>
