          </div>
      </div>

      {/* Configuration Modal */}
      {selectedLevel && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setSelectedLevel(null)} />

          <div className="relative w-full max-w-md bg-zinc-900 border border-zinc-700 rounded-2xl shadow-2xl p-8 flex flex-col space-y-8 animate-in zoom-in-95 duration-200">

             {/* Header */}
             <div className="text-center">
                <div className={`text-sm font-bold text-${selectedLevel.color}-400 tracking-widest uppercase mb-1`}>Mission Configuration</div>
                <h2 className="text-3xl font-orbitron font-bold text-white">{selectedLevel.name}</h2>
