          <div className="flex justify-center gap-8 border-t border-white/10 pt-8">
             <button onClick={quitGame} className="text-xs font-sans text-slate-500 hover:text-white transition-colors tracking-[0.2em] uppercase">
                Gallery
              </button>
              <button onClick={() => startGame(gameConfig)} className={`text-xs font-sans text-${gameConfig.level.color}-300 hover:text-white transition-colors tracking-[0.2em] uppercase font-bold`}>
                Replay
              </button>
          </div>
        </div>
      )}
    </div>
  );
