                <div className="flex justify-between items-baseline border-b border-white/10 pb-2">
                  <label className="text-slate-400 font-sans text-xs tracking-widest uppercase">Tempo</label>
                  <span className={`text-3xl font-serif italic text-${selectedLevel.color}-200`}>{bpm} <span className="text-xs font-sans text-slate-500 not-italic">BPM</span></span>
                </div>
                <input 
                  type="range" 
                  min="60" 
                  max="240" 
                  value={bpm} 
                  onChange={(e) => setBpm(parseInt(e.target.value))}
                  className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-white"
                />
             </div>

             {/* Difficulty Selector */}
             <div className="space-y-6">
                <label className="text-slate-400 font-sans text-xs tracking-widest uppercase block text-center">Difficulty</label>
                <div className="flex justify-center gap-4">
                   {[Difficulty.EASY, Difficulty.MEDIUM, Difficulty.HARD].map((d) => (
                      <button
                        key={d}
                        onClick={() => setDifficulty(d)}
                        className={`px-6 py-3 text-xs font-sans tracking-widest uppercase transition-all duration-300 border ${
                          difficulty === d 
                            ? `bg-white text-black border-white` 
                            : 'bg-transparent text-slate-500 border-white/10 hover:border-white/30 hover:text-white'
                        }`}
                      >
                        {d}
                      </button>
                   ))}
                </div>
                <div className="text-center text-xs font-serif italic text-slate-400 min-h-[1.5em]">
                   {difficulty === Difficulty.EASY && "Generous timing windows."}
                   {difficulty === Difficulty.MEDIUM && "Standard precision required."}
                   {difficulty === Difficulty.HARD && "Millisecond precision only."}
                </div>
             </div>

             {/* Actions */}
             <div className="flex space-x-0 pt-8 border-t border-white/5">
               <button 
                  onClick={() => setSelectedLevel(null)}
                  className="flex-1 py-4 text-slate-500 hover:text-white transition-colors font-sans text-xs tracking-[0.2em] uppercase"
               >
                 Back
               </button>
               <div className="w-px bg-white/10 mx-4"></div>
               <button 
                  onClick={handleStart}
                  className={`flex-1 py-4 text-${selectedLevel.color}-300 hover:text-white transition-colors font-sans text-xs font-bold tracking-[0.2em] uppercase`}
               >
                 Start
               </button>
             </div>

          </div>
        </div>
      )}
    </>
  );
};

export default LevelSelector;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level, Difficulty, GameConfig, HighScores } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds
const GAME_DURATION = 30.0; // seconds

// Scoring Windows (ms) for [Perfect+, Perfect, Great, Good]
const SCORING_WINDOWS = {
  [Difficulty.EASY]:   [40, 70, 130, 200],
  [Difficulty.MEDIUM]: [25, 50, 100, 150],
  [Difficulty.HARD]:   [15, 30, 60, 100]
};

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [gameConfig, setGameConfig] = useState<GameConfig | null>(null);

  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);
  const [timeLeft, setTimeLeft] = useState(GAME_DURATION);
  const [isCountIn, setIsCountIn] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const noiseBuffer = useRef<AudioBuffer | null>(null); 

  const nextNoteTime = useRef<number>(0.0); 
  const nextMetronomeTime = useRef<number>(0.0); 

  const currentBeatInPattern = useRef<number>(0);
  const timerID = useRef<number | null>(null);
  const loopStartTime = useRef<number>(0);
  const gameStartTime = useRef<number>(0); // When scoring actually begins

  // Queue for scoring
  const expectedHits = useRef<Array<{ time: number, processed: boolean }>>([]);
  const [beatTrigger, setBeatTrigger] = useState(0);

  // Initialize Audio
  const initAudio = async () => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    if (!noiseBuffer.current) {
      const bufferSize = audioContext.current.sampleRate * 2.0; 
      const buffer = audioContext.current.createBuffer(1, bufferSize, audioContext.current.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
      }
      noiseBuffer.current = buffer;
    }
  };

  const playKick = useCallback((time: number) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(50, time + 0.1);

    gain.gain.setValueAtTime(0.5, time); // Softer kick
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const playHiHat = useCallback((time: number) => {
    if (!audioContext.current || !noiseBuffer.current) return;
    const ctx = audioContext.current;

    const source = ctx.createBufferSource();
    source.buffer = noiseBuffer.current;

    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 7000;

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.2, time); // Softer hat
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    source.start(time);
    source.stop(time + 0.1);
  }, []);

  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    expectedHits.current.push({ time: time, processed: false });
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);
    playHiHat(time);
  }, [playHiHat]);

  const endGame = useCallback(async () => {
    if (gameConfig) {
      const stored = localStorage.getItem('rhythmPulseScores');
      let scores: HighScores = stored ? JSON.parse(stored) : {};

      const currentLevelScores = scores[gameConfig.level.id] || {};
      const previousEntry = currentLevelScores[gameConfig.difficulty];
      const previousBestScore = typeof previousEntry === 'number' ? previousEntry : (previousEntry?.score || 0);

      setStats(currentStats => {
        if (currentStats.totalScore > previousBestScore) {
          scores = {
            ...scores,
            [gameConfig.level.id]: {
              ...currentLevelScores,
              [gameConfig.difficulty]: {
                  score: Math.floor(currentStats.totalScore),
                  accuracy: currentStats.averageAccuracy
              }
            }
          };
          localStorage.setItem('rhythmPulseScores', JSON.stringify(scores));
        }

        setLoadingAI(true);
        getAICommentary({
            perfects: currentStats.perfects,
            misses: currentStats.misses,
            averageAccuracy: currentStats.averageAccuracy
        }).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });

        return currentStats;
      });
    }

    if (audioContext.current) {
        audioContext.current.suspend();
    }
    setGameState(GameState.RESULTS);
  }, [gameConfig]);

  const scheduler = useCallback(() => {
    if (!gameConfig || !audioContext.current || gameState !== GameState.PLAYING) return;
    if (audioContext.current.state === 'suspended') return;

    const currentTime = audioContext.current.currentTime;

    // Timer Logic
    // If current time is less than gameStartTime, we are in count-in
    const elapsedTime = currentTime - gameStartTime.current;

    if (elapsedTime < 0) {
        setIsCountIn(true);
        setTimeLeft(GAME_DURATION); // Freeze timer at max
    } else {
        setIsCountIn(false);
        const remaining = Math.max(0, GAME_DURATION - elapsedTime);
        setTimeLeft(remaining);
        if (remaining <= 0) {
            endGame();
            return;
        }
    }

    const beatDuration = 60 / gameConfig.bpm;

    while (nextMetronomeTime.current < currentTime + SCHEDULE_AHEAD_TIME) {
        playKick(nextMetronomeTime.current);
        const timeToNote = (nextMetronomeTime.current - currentTime) * 1000;
        setTimeout(() => {
            if (gameState === GameState.PLAYING) setBeatTrigger(prev => prev + 1);
        }, Math.max(0, timeToNote));
        nextMetronomeTime.current += beatDuration;
    }

    while (nextNoteTime.current < currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);
        const pattern = gameConfig.level.pattern;
        const currentBeatVal = pattern[currentBeatInPattern.current];
        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];
        let beatDiff = nextIndex === 0 ? gameConfig.level.loopBeats - currentBeatVal + nextBeatVal : nextBeatVal - currentBeatVal;
        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }
    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [gameConfig, gameState, scheduleNote, playKick, endGame]);

  useEffect(() => {
      let isActive = true;
      if (gameState === GameState.PLAYING && gameConfig && audioContext.current) {
          if (audioContext.current.state === 'suspended') {
              audioContext.current.resume().then(() => { if (isActive) scheduler(); });
          } else { scheduler(); }
      } else if (gameState === GameState.PAUSED && audioContext.current) {
          audioContext.current.suspend();
          if (timerID.current) window.clearTimeout(timerID.current);
      }
      return () => {
          isActive = false;
          if (timerID.current) window.clearTimeout(timerID.current);
      };
  }, [gameState, gameConfig, scheduler]);

  const selectLevel = (config: GameConfig) => {
      setGameConfig(config);
      startGame(config);
  };

  const startGame = async (config: GameConfig) => {
    await initAudio();
    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0, combo: 0, maxCombo: 0, perfects: 0, greats: 0, goods: 0, misses: 0, averageAccuracy: 0
    });
    setAiComment("");
    setLastHit(null);
    setTimeLeft(GAME_DURATION);
    setIsCountIn(true);
    expectedHits.current = [];

    // Short delay to show "Ready" then start audio
    setTimeout(() => {
      if (audioContext.current) {
          const now = audioContext.current.currentTime;
          const beatDuration = 60 / config.bpm;
          // Count in duration: 2 bars of 4/4 = 8 beats
          const countInDuration = beatDuration * 8; 

          const audioStartTime = now + 0.1;

          nextMetronomeTime.current = audioStartTime; 
          nextNoteTime.current = audioStartTime + (config.level.pattern[0] * beatDuration); 
          loopStartTime.current = audioStartTime;

          // Game starts (scoring begins) after count-in
          gameStartTime.current = audioStartTime + countInDuration; 
          currentBeatInPattern.current = 0;
      }
      setGameState(GameState.PLAYING);
    }, 1000);
  };

  const togglePause = useCallback(() => {
      if (gameState === GameState.PLAYING) setGameState(GameState.PAUSED);
      else if (gameState === GameState.PAUSED) setGameState(GameState.PLAYING);
  }, [gameState]);

  const quitGame = useCallback(() => {
      if (audioContext.current) audioContext.current.suspend();
      setGameState(GameState.IDLE);
      setGameConfig(null);
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current || !gameConfig) return;

    const tapTime = audioContext.current.currentTime;

    // Ignore input during count-in
    if (tapTime < gameStartTime.current) return;

    const activeHits = expectedHits.current.filter(h => !h.processed);

    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        // Only score hits that are part of the game session (not left over from count in, though cleaning happens)
        // Since expectedHits are cleaned by scheduler, we just check diff.
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) { minDiff = diff; closestHit = hit; }
    }

    const diffMs = minDiff * 1000;
    let score = 0;
    let label = "Miss";
    let color = "text-red-400";

    const windows = SCORING_WINDOWS[gameConfig.difficulty];

    if (closestHit && diffMs < windows[3]) {
        closestHit.processed = true;
        if (diffMs < windows[0]) {
             score = 100; label = "Perfect"; color = "text-white drop-shadow-[0_0_10px_white]";
        } else if (diffMs < windows[1]) {
             score = 90 + Math.floor((windows[1] - diffMs)/(windows[1]-windows[0]) * 10);
             label = "Perfect"; color = `text-${gameConfig.level.color}-200`;
        } else if (diffMs < windows[2]) {
             score = 70 + Math.floor((windows[2] - diffMs)/(windows[2]-windows[1]) * 20);
             label = "Great"; color = `text-${gameConfig.level.color}-300`;
        } else {
             score = 40 + Math.floor((windows[3] - diffMs)/(windows[3]-windows[2]) * 30);
             label = "Good"; color = "text-yellow-200";
        }
    } else {
        score = 0; label = "Miss"; color = "text-red-400/50";
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;
      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, gameConfig]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') { e.preventDefault(); handleTap(); } 
      else if (e.code === 'Escape') { if (gameState === GameState.PLAYING || gameState === GameState.PAUSED) togglePause(); } 
      else if (e.code === 'KeyQ') { if (gameState === GameState.PAUSED) quitGame(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap, togglePause, gameState, quitGame]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden font-sans">

      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={gameConfig.level}
            bpm={gameConfig.bpm}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {gameState === GameState.STARTING && gameConfig && (
        <div className="z-10 text-center animate-in fade-in duration-500">
           <div className={`text-lg font-serif italic text-${gameConfig.level.color}-200 mb-4 opacity-70`}>Syncing...</div>
           <div className="text-8xl font-serif text-white tracking-tight">Ready</div>
        </div>
      )}

      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <>
          {/* Elegant Progress Line */}
          <div className="absolute top-0 left-0 w-full z-20">
             <div className="h-0.5 w-full bg-white/5">
                <div 
                  className={`h-full bg-${gameConfig.level.color}-300 shadow-[0_0_15px_currentColor] transition-all duration-100 ease-linear`}
                  style={{ width: `${(timeLeft / GAME_DURATION) * 100}%` }}
                ></div>
             </div>
          </div>

          <div className="absolute top-8 left-8 right-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className="text-5xl font-serif text-white/90">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
                 <div className="flex items-center gap-4 mt-2">
                    <span className={`text-xs font-sans tracking-[0.2em] text-${gameConfig.level.color}-200 uppercase`}>{gameConfig.level.name}</span>
                    <span className="text-xs font-serif italic text-slate-500">{gameConfig.difficulty}</span>
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className={`text-5xl font-serif ${stats.averageAccuracy > 95 ? 'text-white' : 'text-slate-300'}`}>
                     {stats.averageAccuracy.toFixed(1)}<span className="text-2xl opacity-50">%</span>
                 </div>
                 <div className="text-xs font-sans text-slate-500 tracking-[0.2em] mt-2 uppercase">Accuracy</div>
             </div>
          </div>

          {gameState === GameState.PLAYING && (
            <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
                {isCountIn ? (
                  <div className="animate-pulse text-center">
                    <div className="text-2xl font-serif italic text-white/50 mb-2">Listen...</div>
                    <div className={`text-6xl font-sans font-bold text-${gameConfig.level.color}-400/80`}>Count In</div>
                  </div>
                ) : (
                  <div className={`text-7xl font-serif italic transition-all duration-500 transform ${lastHit ? 'scale-100 opacity-100 translate-y-0 blur-0' : 'scale-95 opacity-0 translate-y-2 blur-sm'} ${lastHit?.color}`}>
                    {lastHit?.label}
                  </div>
                )}
            </div>
          )}

          {gameState === GameState.PAUSED && (
            <div className="absolute inset-0 z-50 bg-black/40 backdrop-blur-lg flex flex-col items-center justify-center animate-in fade-in duration-500">
                <h2 className="text-5xl font-serif italic text-white mb-12">Paused</h2>
                <div className="flex flex-col space-y-6 w-64 items-center">
                    <button onClick={togglePause} className="text-sm font-sans tracking-[0.3em] text-white hover:scale-105 transition-transform uppercase">
                        Resume
                    </button>
                    <button onClick={quitGame} className="text-xs font-sans tracking-[0.3em] text-slate-500 hover:text-white transition-colors uppercase">
                        Exit
                    </button>
                </div>
            </div>
          )}

          {stats.combo > 5 && gameState === GameState.PLAYING && !isCountIn && (
              <div className="absolute bottom-1/4 z-10 animate-pulse duration-1000">
                  <div className={`text-3xl font-serif italic text-${gameConfig.level.color}-300 opacity-60`}>
                      {stats.combo} Combo
                  </div>
              </div>
          )}
        </>
      )}

      {gameState === GameState.RESULTS && gameConfig && (
        <div className="z-20 w-full max-w-2xl bg-[#0a0a0a]/80 backdrop-blur-xl border border-white/10 p-16 shadow-2xl animate-in fade-in zoom-in-95 duration-700">
          <div className="text-center mb-12">
            <h2 className="text-5xl font-serif italic text-white mb-2">Results</h2>
            <div className={`text-xs font-sans tracking-[0.3em] text-${gameConfig.level.color}-300 uppercase`}>
                {gameConfig.level.name}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-16 mb-12">
             <div className="flex flex-col justify-center space-y-4">
                 <StatRow label="Perfect" count={stats.perfects} color="text-white" />
                 <StatRow label="Great" count={stats.greats} color="text-slate-300" />
                 <StatRow label="Good" count={stats.goods} color="text-slate-400" />
                 <StatRow label="Miss" count={stats.misses} color="text-slate-600" />
             </div>

             <div className="flex flex-col justify-center items-center border-l border-white/5 pl-8">
                 <div className="text-xs font-sans text-slate-500 tracking-widest uppercase mb-2">Accuracy</div>
                 <div className="text-6xl font-serif text-white mb-8">{stats.averageAccuracy.toFixed(1)}%</div>

                 <div className="text-xs font-sans text-slate-500 tracking-widest uppercase mb-2">Score</div>
                 <div className={`text-3xl font-serif text-${gameConfig.level.color}-300`}>{Math.floor(stats.totalScore).toLocaleString()}</div>
             </div>
          </div>

          <div className="text-center mb-10">
            <div className="text-2xl font-serif italic text-slate-300 leading-relaxed">
                {loadingAI ? <span className="animate-pulse">Analyzing...</span> : `"${aiComment}"`}
            </div>
            <div className="text-[10px] text-slate-600 mt-2 font-sans uppercase tracking-widest">Feedback</div>
          </div>

          <div className="flex justify-center gap-8 border-t border-white/10 pt-8">
             <button onClick={quitGame} className="text-xs font-sans text-slate-500 hover:text-white transition-colors tracking-[0.2em] uppercase">
                Back
              </button>
              <button onClick={() => startGame(gameConfig)} className={`text-xs font-sans text-${gameConfig.level.color}-300 hover:text-white transition-colors tracking-[0.2em] uppercase font-bold`}>
                Retry
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

const StatRow = ({ label, count, color }: { label: string, count: number, color: string }) => (
    <div className="flex justify-between items-baseline group border-b border-white/5 pb-2 last:border-0">
        <span className="text-slate-500 text-xs font-sans tracking-widest uppercase">{label}</span>
        <span className={`text-xl font-serif ${color}`}>{count}</span>
    </div>
);

export default RhythmEngine;

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export interface AnalysisStats {
  perfects: number;
  misses: number;
  averageAccuracy: number;
  earlyRate: number; // Percentage of hits that were early
  lateRate: number; // Percentage of hits that were late
  offbeatMisses: number;
  downbeatMisses: number;
  trend: 'improving' | 'degrading' | 'stable';
}

export const getAICommentary = async (stats: AnalysisStats) => {
  try {
    const prompt = `You are a strict technical rhythm coach. Analyze these performance stats for a rhythm game player:
    - Accuracy: ${stats.averageAccuracy.toFixed(1)}%
    - Timing Bias: ${stats.earlyRate > 55 ? 'Rushing (Early)' : stats.lateRate > 55 ? 'Dragging (Late)' : 'Balanced'}
    - Misses: ${stats.misses} (Offbeat Misses: ${stats.offbeatMisses}, Downbeat Misses: ${stats.downbeatMisses})
    - Trend: ${stats.trend}

    Provide a single, short, actionable sentence of feedback.
    - If they rush (>55% early), tell them to relax or wait for the beat.
    - If they drag (>55% late), tell them to anticipate the beat or speed up.
    - If they miss offbeats, tell them to focus on the subdivisions/"ands".
    - If accuracy degrades, mention stamina or focus.
    - If accuracy is >95% and balanced, praise their timing.
    - Do NOT be "quirky". Be professional and direct. Maximum 20 words.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7, // Lower temperature for more consistent/focused advice
      }
    });

    return response.text || "Focus on maintaining a steady internal pulse.";
  } catch (error) {
    console.error("Gemini Commentary Error:", error);
    return "Listen closely to the metronome and try to center your hits.";
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level, Difficulty, GameConfig, HighScores } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary, AnalysisStats } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds
const GAME_DURATION = 30.0; // seconds

// Scoring Windows (ms) for [Perfect+, Perfect, Great, Good]
const SCORING_WINDOWS = {
  [Difficulty.EASY]:   [40, 70, 130, 200],
  [Difficulty.MEDIUM]: [25, 50, 100, 150],
  [Difficulty.HARD]:   [15, 30, 60, 100]
};

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [gameConfig, setGameConfig] = useState<GameConfig | null>(null);

  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);
  const [timeLeft, setTimeLeft] = useState(GAME_DURATION);
  const [isCountIn, setIsCountIn] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const noiseBuffer = useRef<AudioBuffer | null>(null); 

  const nextNoteTime = useRef<number>(0.0); 
  const nextMetronomeTime = useRef<number>(0.0); 

  const currentBeatInPattern = useRef<number>(0);
  const timerID = useRef<number | null>(null);
  const loopStartTime = useRef<number>(0);
  const gameStartTime = useRef<number>(0); // When scoring actually begins

  // Queue for scoring
  const expectedHits = useRef<Array<{ time: number, beat: number, processed: boolean }>>([]);
  // Detailed hit history for analysis
  const hitHistory = useRef<Array<{ rawDiff: number; isMiss: boolean; beat: number; timestamp: number }>>([]);
  const [beatTrigger, setBeatTrigger] = useState(0);

  // Initialize Audio
  const initAudio = async () => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    if (!noiseBuffer.current) {
      const bufferSize = audioContext.current.sampleRate * 2.0; 
      const buffer = audioContext.current.createBuffer(1, bufferSize, audioContext.current.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
      }
      noiseBuffer.current = buffer;
    }
  };

  const playKick = useCallback((time: number) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(50, time + 0.1);

    gain.gain.setValueAtTime(0.5, time); // Softer kick
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const playHiHat = useCallback((time: number) => {
    if (!audioContext.current || !noiseBuffer.current) return;
    const ctx = audioContext.current;

    const source = ctx.createBufferSource();
    source.buffer = noiseBuffer.current;

    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 7000;

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.2, time); // Softer hat
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    source.start(time);
    source.stop(time + 0.1);
  }, []);

  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    // Store beat info (integer part is downbeat, decimal is offbeat)
    expectedHits.current.push({ time: time, beat: beatNumber, processed: false });
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);
    playHiHat(time);
  }, [playHiHat]);

  const endGame = useCallback(async () => {
    if (gameConfig) {
      const stored = localStorage.getItem('rhythmPulseScores');
      let scores: HighScores = stored ? JSON.parse(stored) : {};

      const currentLevelScores = scores[gameConfig.level.id] || {};
      const previousEntry = currentLevelScores[gameConfig.difficulty];
      const previousBestScore = typeof previousEntry === 'number' ? previousEntry : (previousEntry?.score || 0);

      setStats(currentStats => {
        if (currentStats.totalScore > previousBestScore) {
          scores = {
            ...scores,
            [gameConfig.level.id]: {
              ...currentLevelScores,
              [gameConfig.difficulty]: {
                  score: Math.floor(currentStats.totalScore),
                  accuracy: currentStats.averageAccuracy
              }
            }
          };
          localStorage.setItem('rhythmPulseScores', JSON.stringify(scores));
        }

        // --- detailed analysis for AI ---
        const history = hitHistory.current;
        const totalHits = history.length;

        // Calculate timing bias (Early vs Late)
        // We consider significant rushing/dragging as > 15ms deviation
        const earlyCount = history.filter(h => h.rawDiff < -15).length;
        const lateCount = history.filter(h => h.rawDiff > 15).length;
        const earlyRate = totalHits > 0 ? (earlyCount / totalHits) * 100 : 0;
        const lateRate = totalHits > 0 ? (lateCount / totalHits) * 100 : 0;

        // Calculate beat specific misses
        const offbeatMisses = history.filter(h => h.isMiss && h.beat % 1 !== 0).length;
        const downbeatMisses = history.filter(h => h.isMiss && h.beat % 1 === 0).length;

        // Calculate Trend (First half accuracy vs Second half accuracy)
        let trend: 'improving' | 'degrading' | 'stable' = 'stable';
        if (totalHits > 4) {
          const midPoint = Math.floor(totalHits / 2);
          const firstHalf = history.slice(0, midPoint);
          const secondHalf = history.slice(midPoint);

          const getAvgAbsDiff = (arr: typeof history) => arr.reduce((acc, curr) => acc + Math.abs(curr.rawDiff), 0) / arr.length;
          const firstAvg = getAvgAbsDiff(firstHalf);
          const secondAvg = getAvgAbsDiff(secondHalf);

          // If second half error is 20% higher than first half -> Degrading
          if (secondAvg > firstAvg * 1.2) trend = 'degrading';
          // If second half error is 20% lower than first half -> Improving
          else if (secondAvg < firstAvg * 0.8) trend = 'improving';
        }

        const analysisStats: AnalysisStats = {
            perfects: currentStats.perfects,
            misses: currentStats.misses,
            averageAccuracy: currentStats.averageAccuracy,
            earlyRate,
            lateRate,
            offbeatMisses,
            downbeatMisses,
            trend
        };

        setLoadingAI(true);
        getAICommentary(analysisStats).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });

        return currentStats;
      });
    }

    if (audioContext.current) {
        audioContext.current.suspend();
    }
    setGameState(GameState.RESULTS);
  }, [gameConfig]);

  const scheduler = useCallback(() => {
    if (!gameConfig || !audioContext.current || gameState !== GameState.PLAYING) return;
    if (audioContext.current.state === 'suspended') return;

    const currentTime = audioContext.current.currentTime;

    // Timer Logic
    // If current time is less than gameStartTime, we are in count-in
    const elapsedTime = currentTime - gameStartTime.current;

    if (elapsedTime < 0) {
        setIsCountIn(true);
        setTimeLeft(GAME_DURATION); // Freeze timer at max
    } else {
        setIsCountIn(false);
        const remaining = Math.max(0, GAME_DURATION - elapsedTime);
        setTimeLeft(remaining);
        if (remaining <= 0) {
            endGame();
            return;
        }
    }

    const beatDuration = 60 / gameConfig.bpm;

    while (nextMetronomeTime.current < currentTime + SCHEDULE_AHEAD_TIME) {
        playKick(nextMetronomeTime.current);
        const timeToNote = (nextMetronomeTime.current - currentTime) * 1000;
        setTimeout(() => {
            if (gameState === GameState.PLAYING) setBeatTrigger(prev => prev + 1);
        }, Math.max(0, timeToNote));
        nextMetronomeTime.current += beatDuration;
    }

    while (nextNoteTime.current < currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);
        const pattern = gameConfig.level.pattern;
        const currentBeatVal = pattern[currentBeatInPattern.current];
        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];
        let beatDiff = nextIndex === 0 ? gameConfig.level.loopBeats - currentBeatVal + nextBeatVal : nextBeatVal - currentBeatVal;
        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }
    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [gameConfig, gameState, scheduleNote, playKick, endGame]);

  useEffect(() => {
      let isActive = true;
      if (gameState === GameState.PLAYING && gameConfig && audioContext.current) {
          if (audioContext.current.state === 'suspended') {
              audioContext.current.resume().then(() => { if (isActive) scheduler(); });
          } else { scheduler(); }
      } else if (gameState === GameState.PAUSED && audioContext.current) {
          audioContext.current.suspend();
          if (timerID.current) window.clearTimeout(timerID.current);
      }
      return () => {
          isActive = false;
          if (timerID.current) window.clearTimeout(timerID.current);
      };
  }, [gameState, gameConfig, scheduler]);

  const selectLevel = (config: GameConfig) => {
      setGameConfig(config);
      startGame(config);
  };

  const startGame = async (config: GameConfig) => {
    await initAudio();
    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0, combo: 0, maxCombo: 0, perfects: 0, greats: 0, goods: 0, misses: 0, averageAccuracy: 0
    });
    setAiComment("");
    setLastHit(null);
    setTimeLeft(GAME_DURATION);
    setIsCountIn(true);
    expectedHits.current = [];
    hitHistory.current = []; // Clear history

    // Short delay to show "Ready" then start audio
    setTimeout(() => {
      if (audioContext.current) {
          const now = audioContext.current.currentTime;
          const beatDuration = 60 / config.bpm;
          // Count in duration: 2 bars of 4/4 = 8 beats
          const countInDuration = beatDuration * 8; 

          const audioStartTime = now + 0.1;

          nextMetronomeTime.current = audioStartTime; 
          nextNoteTime.current = audioStartTime + (config.level.pattern[0] * beatDuration); 
          loopStartTime.current = audioStartTime;

          // Game starts (scoring begins) after count-in
          gameStartTime.current = audioStartTime + countInDuration; 
          currentBeatInPattern.current = 0;
      }
      setGameState(GameState.PLAYING);
    }, 1000);
  };

  const togglePause = useCallback(() => {
      if (gameState === GameState.PLAYING) setGameState(GameState.PAUSED);
      else if (gameState === GameState.PAUSED) setGameState(GameState.PLAYING);
  }, [gameState]);

  const quitGame = useCallback(() => {
      if (audioContext.current) audioContext.current.suspend();
      setGameState(GameState.IDLE);
      setGameConfig(null);
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current || !gameConfig) return;

    const tapTime = audioContext.current.currentTime;

    // Ignore input during count-in
    if (tapTime < gameStartTime.current) return;

    const activeHits = expectedHits.current.filter(h => !h.processed);

    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) { minDiff = diff; closestHit = hit; }
    }

    const diffMs = minDiff * 1000;
    let score = 0;
    let label = "Miss";
    let color = "text-red-400";

    const windows = SCORING_WINDOWS[gameConfig.difficulty];

    let rawDiff = 0; // Positive = Late, Negative = Early
    let isMiss = true;

    if (closestHit) {
      rawDiff = (tapTime - closestHit.time) * 1000;
    }

    if (closestHit && diffMs < windows[3]) {
        closestHit.processed = true;
        isMiss = false;
        if (diffMs < windows[0]) {
             score = 100; label = "Perfect"; color = "text-white drop-shadow-[0_0_10px_white]";
        } else if (diffMs < windows[1]) {
             score = 90 + Math.floor((windows[1] - diffMs)/(windows[1]-windows[0]) * 10);
             label = "Perfect"; color = `text-${gameConfig.level.color}-200`;
        } else if (diffMs < windows[2]) {
             score = 70 + Math.floor((windows[2] - diffMs)/(windows[2]-windows[1]) * 20);
             label = "Great"; color = `text-${gameConfig.level.color}-300`;
        } else {
             score = 40 + Math.floor((windows[3] - diffMs)/(windows[3]-windows[2]) * 30);
             label = "Good"; color = "text-yellow-200";
        }
    } else {
        score = 0; label = "Miss"; color = "text-red-400/50";
        // If we missed, rawDiff might be huge if closestHit is far, or undefined if no hit. 
        // We still record it if closestHit exists to track beat pattern issues, 
        // but we might clamp diff or treat it purely as a miss.
    }

    // Record stats for AI analysis
    if (closestHit) {
      hitHistory.current.push({
        rawDiff: rawDiff,
        isMiss: isMiss,
        beat: closestHit.beat,
        timestamp: tapTime
      });
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;
      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, gameConfig]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') { e.preventDefault(); handleTap(); } 
      else if (e.code === 'Escape') { if (gameState === GameState.PLAYING || gameState === GameState.PAUSED) togglePause(); } 
      else if (e.code === 'KeyQ') { if (gameState === GameState.PAUSED) quitGame(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap, togglePause, gameState, quitGame]);

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden font-sans">

      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={gameConfig.level}
            bpm={gameConfig.bpm}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {gameState === GameState.STARTING && gameConfig && (
        <div className="z-10 text-center animate-in fade-in duration-500">
           <div className={`text-lg font-serif italic text-${gameConfig.level.color}-200 mb-4 opacity-70`}>Syncing...</div>
           <div className="text-8xl font-serif text-white tracking-tight">Ready</div>
        </div>
      )}

      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <>
          {/* Elegant Progress Line */}
          <div className="absolute top-0 left-0 w-full z-20">
             <div className="h-0.5 w-full bg-white/5">
                <div 
                  className={`h-full bg-${gameConfig.level.color}-300 shadow-[0_0_15px_currentColor] transition-all duration-100 ease-linear`}
                  style={{ width: `${(timeLeft / GAME_DURATION) * 100}%` }}
                ></div>
             </div>
          </div>

          <div className="absolute top-8 left-8 right-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className="text-5xl font-serif text-white/90">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
                 <div className="flex items-center gap-4 mt-2">
                    <span className={`text-xs font-sans tracking-[0.2em] text-${gameConfig.level.color}-200 uppercase`}>{gameConfig.level.name}</span>
                    <span className="text-xs font-serif italic text-slate-500">{gameConfig.difficulty}</span>
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className={`text-5xl font-serif ${stats.averageAccuracy > 95 ? 'text-white' : 'text-slate-300'}`}>
                     {stats.averageAccuracy.toFixed(1)}<span className="text-2xl opacity-50">%</span>
                 </div>
                 <div className="text-xs font-sans text-slate-500 tracking-[0.2em] mt-2 uppercase">Accuracy</div>
             </div>
          </div>

          {gameState === GameState.PLAYING && (
            <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
                {isCountIn ? (
                  <div className="animate-pulse text-center">
                    <div className="text-2xl font-serif italic text-white/50 mb-2">Listen...</div>
                    <div className={`text-6xl font-sans font-bold text-${gameConfig.level.color}-400/80`}>Count In</div>
                  </div>
                ) : (
                  <div className={`text-7xl font-serif italic transition-all duration-500 transform ${lastHit ? 'scale-100 opacity-100 translate-y-0 blur-0' : 'scale-95 opacity-0 translate-y-2 blur-sm'} ${lastHit?.color}`}>
                    {lastHit?.label}
                  </div>
                )}
            </div>
          )}

          {gameState === GameState.PAUSED && (
            <div className="absolute inset-0 z-50 bg-black/40 backdrop-blur-lg flex flex-col items-center justify-center animate-in fade-in duration-500">
                <h2 className="text-5xl font-serif italic text-white mb-12">Paused</h2>
                <div className="flex flex-col space-y-6 w-64 items-center">
                    <button onClick={togglePause} className="text-sm font-sans tracking-[0.3em] text-white hover:scale-105 transition-transform uppercase">
                        Resume
                    </button>
                    <button onClick={quitGame} className="text-xs font-sans tracking-[0.3em] text-slate-500 hover:text-white transition-colors uppercase">
                        Exit
                    </button>
                </div>
            </div>
          )}

          {stats.combo > 5 && gameState === GameState.PLAYING && !isCountIn && (
              <div className="absolute bottom-1/4 z-10 animate-pulse duration-1000">
                  <div className={`text-3xl font-serif italic text-${gameConfig.level.color}-300 opacity-60`}>
                      {stats.combo} Combo
                  </div>
              </div>
          )}
        </>
      )}

      {gameState === GameState.RESULTS && gameConfig && (
        <div className="z-20 w-full max-w-2xl bg-[#0a0a0a]/80 backdrop-blur-xl border border-white/10 p-16 shadow-2xl animate-in fade-in zoom-in-95 duration-700">
          <div className="text-center mb-12">
            <h2 className="text-5xl font-serif italic text-white mb-2">Results</h2>
            <div className={`text-xs font-sans tracking-[0.3em] text-${gameConfig.level.color}-300 uppercase`}>
                {gameConfig.level.name}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-16 mb-12">
             <div className="flex flex-col justify-center space-y-4">
                 <StatRow label="Perfect" count={stats.perfects} color="text-white" />
                 <StatRow label="Great" count={stats.greats} color="text-slate-300" />
                 <StatRow label="Good" count={stats.goods} color="text-slate-400" />
                 <StatRow label="Miss" count={stats.misses} color="text-slate-600" />
             </div>

             <div className="flex flex-col justify-center items-center border-l border-white/5 pl-8">
                 <div className="text-xs font-sans text-slate-500 tracking-widest uppercase mb-2">Accuracy</div>
                 <div className="text-6xl font-serif text-white mb-8">{stats.averageAccuracy.toFixed(1)}%</div>

                 <div className="text-xs font-sans text-slate-500 tracking-widest uppercase mb-2">Score</div>
                 <div className={`text-3xl font-serif text-${gameConfig.level.color}-300`}>{Math.floor(stats.totalScore).toLocaleString()}</div>
             </div>
          </div>

          <div className="text-center mb-10">
            <div className="text-2xl font-serif italic text-slate-300 leading-relaxed">
                {loadingAI ? <span className="animate-pulse">Analyzing...</span> : `"${aiComment}"`}
            </div>
            <div className="text-[10px] text-slate-600 mt-2 font-sans uppercase tracking-widest">Coach Feedback</div>
          </div>

          <div className="flex justify-center gap-8 border-t border-white/10 pt-8">
             <button onClick={quitGame} className="text-xs font-sans text-slate-500 hover:text-white transition-colors tracking-[0.2em] uppercase">
                Back
              </button>
              <button onClick={() => startGame(gameConfig)} className={`text-xs font-sans text-${gameConfig.level.color}-300 hover:text-white transition-colors tracking-[0.2em] uppercase font-bold`}>
                Retry
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

const StatRow = ({ label, count, color }: { label: string, count: number, color: string }) => (
    <div className="flex justify-between items-baseline group border-b border-white/5 pb-2 last:border-0">
        <span className="text-slate-500 text-xs font-sans tracking-widest uppercase">{label}</span>
        <span className={`text-xl font-serif ${color}`}>{count}</span>
    </div>
);

export default RhythmEngine;

export enum GameState {
  IDLE = 'IDLE', // Level Selection
  STARTING = 'STARTING',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  RESULTS = 'RESULTS'
}

export enum Difficulty {
  EASY = 'EASY',
  MEDIUM = 'MEDIUM',
  HARD = 'HARD'
}

export interface Level {
  id: string;
  name: string;
  description: string;
  bpm: number;
  loopBeats: number; // Length of the pattern in beats (e.g., 4 for a measure, 8 for 2 measures)
  pattern: number[]; // Beat positions (e.g., [0, 1, 2, 3])
  color: string; // Tailwind color class base (e.g. 'cyan')
  hex: string; // Hex code for canvas
}

export interface GameConfig {
  level: Level;
  bpm: number;
  difficulty: Difficulty;
}

export interface ScoreEntry {
  score: number;
  timestamp: number;
  label: string;
  color: string;
}

export interface HitEvent {
  offset: number; // ms difference. negative = early, positive = late
  timestamp: number; // relative to song start in seconds
  score: number;
  isMiss: boolean;
  beat: number;
}

export interface GameStats {
  totalScore: number;
  combo: number;
  maxCombo: number;
  perfects: number;
  greats: number;
  goods: number;
  misses: number;
  averageAccuracy: number;
  history: HitEvent[];
}

export interface HighScoreEntry {
  score: number;
  accuracy: number;
}

export interface HighScores {
  [levelId: string]: {
    [key in Difficulty]?: HighScoreEntry | number;
  };
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export interface AnalysisStats {
  perfects: number;
  misses: number;
  averageAccuracy: number;
  earlyRate: number; // Percentage of hits that were early
  lateRate: number; // Percentage of hits that were late
  offbeatMisses: number;
  downbeatMisses: number;
  trend: 'improving' | 'degrading' | 'stable';
}

export const getAICommentary = async (stats: AnalysisStats) => {
  try {
    const prompt = `You are a master percussionist and technical rhythm coach. Analyze these performance stats for a student:
    - Accuracy: ${stats.averageAccuracy.toFixed(1)}%
    - Timing Bias: ${stats.earlyRate.toFixed(1)}% Early (Rushing), ${stats.lateRate.toFixed(1)}% Late (Dragging)
    - Misses: ${stats.misses} (Offbeat Misses: ${stats.offbeatMisses}, Downbeat Misses: ${stats.downbeatMisses})
    - Consistency Trend: ${stats.trend}

    Provide a professional, detailed analysis (approx. 2-3 sentences). 
    1. Diagnose their specific issue (e.g., "You tend to rush when anticipating the downbeat" or "Your internal clock drags on the offbeats").
    2. Offer a specific, technical practice tip to correct this (e.g., "Subdivide the beat in your head," "Relax your wrist," "Focus on the release of the key").
    3. Adopt a serious, encouraging, but strict tone. No slang. Use musical terminology correctly.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
      }
    });

    return response.text || "Maintain a steady internal pulse and focus on subdivision.";
  } catch (error) {
    console.error("Gemini Commentary Error:", error);
    return "Listen closely to the metronome and try to center your hits.";
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level, Difficulty, GameConfig, HighScores, HitEvent } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary, AnalysisStats } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds
const GAME_DURATION = 30.0; // seconds

// Scoring Windows (ms) for [Perfect+, Perfect, Great, Good]
const SCORING_WINDOWS = {
  [Difficulty.EASY]:   [40, 70, 130, 200],
  [Difficulty.MEDIUM]: [25, 50, 100, 150],
  [Difficulty.HARD]:   [15, 30, 60, 100]
};

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [gameConfig, setGameConfig] = useState<GameConfig | null>(null);

  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0,
    history: []
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);
  const [timeLeft, setTimeLeft] = useState(GAME_DURATION);
  const [isCountIn, setIsCountIn] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const noiseBuffer = useRef<AudioBuffer | null>(null); 

  const nextNoteTime = useRef<number>(0.0); 
  const nextMetronomeTime = useRef<number>(0.0); 

  const currentBeatInPattern = useRef<number>(0);
  const timerID = useRef<number | null>(null);
  const loopStartTime = useRef<number>(0);
  const gameStartTime = useRef<number>(0); // When scoring actually begins

  // Queue for scoring
  const expectedHits = useRef<Array<{ time: number, beat: number, processed: boolean }>>([]);
  // Detailed hit history for analysis
  const hitHistory = useRef<Array<HitEvent>>([]);
  const [beatTrigger, setBeatTrigger] = useState(0);

  // Initialize Audio
  const initAudio = async () => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    if (!noiseBuffer.current) {
      const bufferSize = audioContext.current.sampleRate * 2.0; 
      const buffer = audioContext.current.createBuffer(1, bufferSize, audioContext.current.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
      }
      noiseBuffer.current = buffer;
    }
  };

  const playKick = useCallback((time: number) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(50, time + 0.1);

    gain.gain.setValueAtTime(0.5, time); // Softer kick
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const playHiHat = useCallback((time: number) => {
    if (!audioContext.current || !noiseBuffer.current) return;
    const ctx = audioContext.current;

    const source = ctx.createBufferSource();
    source.buffer = noiseBuffer.current;

    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 7000;

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.2, time); // Softer hat
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    source.start(time);
    source.stop(time + 0.1);
  }, []);

  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    // Store beat info (integer part is downbeat, decimal is offbeat)
    expectedHits.current.push({ time: time, beat: beatNumber, processed: false });
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);
    playHiHat(time);
  }, [playHiHat]);

  const endGame = useCallback(async () => {
    if (gameConfig) {
      const stored = localStorage.getItem('rhythmPulseScores');
      let scores: HighScores = stored ? JSON.parse(stored) : {};

      const currentLevelScores = scores[gameConfig.level.id] || {};
      const previousEntry = currentLevelScores[gameConfig.difficulty];
      const previousBestScore = typeof previousEntry === 'number' ? previousEntry : (previousEntry?.score || 0);

      setStats(currentStats => {
        if (currentStats.totalScore > previousBestScore) {
          scores = {
            ...scores,
            [gameConfig.level.id]: {
              ...currentLevelScores,
              [gameConfig.difficulty]: {
                  score: Math.floor(currentStats.totalScore),
                  accuracy: currentStats.averageAccuracy
              }
            }
          };
          localStorage.setItem('rhythmPulseScores', JSON.stringify(scores));
        }

        // --- detailed analysis for AI ---
        const history = hitHistory.current;
        const totalHits = history.length;

        // Calculate timing bias (Early vs Late)
        // We consider significant rushing/dragging as > 15ms deviation
        const earlyCount = history.filter(h => h.offset < -15).length;
        const lateCount = history.filter(h => h.offset > 15).length;
        const earlyRate = totalHits > 0 ? (earlyCount / totalHits) * 100 : 0;
        const lateRate = totalHits > 0 ? (lateCount / totalHits) * 100 : 0;

        // Calculate beat specific misses
        const offbeatMisses = history.filter(h => h.isMiss && h.beat % 1 !== 0).length;
        const downbeatMisses = history.filter(h => h.isMiss && h.beat % 1 === 0).length;

        // Calculate Trend (First half accuracy vs Second half accuracy)
        let trend: 'improving' | 'degrading' | 'stable' = 'stable';
        if (totalHits > 4) {
          const midPoint = Math.floor(totalHits / 2);
          const firstHalf = history.slice(0, midPoint);
          const secondHalf = history.slice(midPoint);

          const getAvgAbsDiff = (arr: typeof history) => arr.reduce((acc, curr) => acc + Math.abs(curr.offset), 0) / arr.length;
          const firstAvg = getAvgAbsDiff(firstHalf);
          const secondAvg = getAvgAbsDiff(secondHalf);

          if (secondAvg > firstAvg * 1.2) trend = 'degrading';
          else if (secondAvg < firstAvg * 0.8) trend = 'improving';
        }

        const analysisStats: AnalysisStats = {
            perfects: currentStats.perfects,
            misses: currentStats.misses,
            averageAccuracy: currentStats.averageAccuracy,
            earlyRate,
            lateRate,
            offbeatMisses,
            downbeatMisses,
            trend
        };

        setLoadingAI(true);
        getAICommentary(analysisStats).then(comment => {
            setAiComment(comment);
            setLoadingAI(false);
        });

        // Add history to final stats state
        return {
            ...currentStats,
            history: history
        };
      });
    }

    if (audioContext.current) {
        audioContext.current.suspend();
    }
    setGameState(GameState.RESULTS);
  }, [gameConfig]);

  const scheduler = useCallback(() => {
    if (!gameConfig || !audioContext.current || gameState !== GameState.PLAYING) return;
    if (audioContext.current.state === 'suspended') return;

    const currentTime = audioContext.current.currentTime;

    // Timer Logic
    const elapsedTime = currentTime - gameStartTime.current;

    if (elapsedTime < 0) {
        setIsCountIn(true);
        setTimeLeft(GAME_DURATION); // Freeze timer at max
    } else {
        setIsCountIn(false);
        const remaining = Math.max(0, GAME_DURATION - elapsedTime);
        setTimeLeft(remaining);
        if (remaining <= 0) {
            endGame();
            return;
        }
    }

    const beatDuration = 60 / gameConfig.bpm;

    while (nextMetronomeTime.current < currentTime + SCHEDULE_AHEAD_TIME) {
        playKick(nextMetronomeTime.current);
        const timeToNote = (nextMetronomeTime.current - currentTime) * 1000;
        setTimeout(() => {
            if (gameState === GameState.PLAYING) setBeatTrigger(prev => prev + 1);
        }, Math.max(0, timeToNote));
        nextMetronomeTime.current += beatDuration;
    }

    while (nextNoteTime.current < currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);
        const pattern = gameConfig.level.pattern;
        const currentBeatVal = pattern[currentBeatInPattern.current];
        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];
        let beatDiff = nextIndex === 0 ? gameConfig.level.loopBeats - currentBeatVal + nextBeatVal : nextBeatVal - currentBeatVal;
        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }
    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [gameConfig, gameState, scheduleNote, playKick, endGame]);

  useEffect(() => {
      let isActive = true;
      if (gameState === GameState.PLAYING && gameConfig && audioContext.current) {
          if (audioContext.current.state === 'suspended') {
              audioContext.current.resume().then(() => { if (isActive) scheduler(); });
          } else { scheduler(); }
      } else if (gameState === GameState.PAUSED && audioContext.current) {
          audioContext.current.suspend();
          if (timerID.current) window.clearTimeout(timerID.current);
      }
      return () => {
          isActive = false;
          if (timerID.current) window.clearTimeout(timerID.current);
      };
  }, [gameState, gameConfig, scheduler]);

  const selectLevel = (config: GameConfig) => {
      setGameConfig(config);
      startGame(config);
  };

  const startGame = async (config: GameConfig) => {
    await initAudio();
    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0, combo: 0, maxCombo: 0, perfects: 0, greats: 0, goods: 0, misses: 0, averageAccuracy: 0, history: []
    });
    setAiComment("");
    setLastHit(null);
    setTimeLeft(GAME_DURATION);
    setIsCountIn(true);
    expectedHits.current = [];
    hitHistory.current = []; // Clear history

    setTimeout(() => {
      if (audioContext.current) {
          const now = audioContext.current.currentTime;
          const beatDuration = 60 / config.bpm;
          const countInDuration = beatDuration * 8; 

          const audioStartTime = now + 0.1;

          nextMetronomeTime.current = audioStartTime; 
          nextNoteTime.current = audioStartTime + (config.level.pattern[0] * beatDuration); 
          loopStartTime.current = audioStartTime;

          gameStartTime.current = audioStartTime + countInDuration; 
          currentBeatInPattern.current = 0;
      }
      setGameState(GameState.PLAYING);
    }, 1000);
  };

  const togglePause = useCallback(() => {
      if (gameState === GameState.PLAYING) setGameState(GameState.PAUSED);
      else if (gameState === GameState.PAUSED) setGameState(GameState.PLAYING);
  }, [gameState]);

  const quitGame = useCallback(() => {
      if (audioContext.current) audioContext.current.suspend();
      setGameState(GameState.IDLE);
      setGameConfig(null);
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current || !gameConfig) return;

    const tapTime = audioContext.current.currentTime;
    if (tapTime < gameStartTime.current) return;

    const activeHits = expectedHits.current.filter(h => !h.processed);

    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) { minDiff = diff; closestHit = hit; }
    }

    const diffMs = minDiff * 1000;
    let score = 0;
    let label = "Miss";
    let color = "text-red-400";

    const windows = SCORING_WINDOWS[gameConfig.difficulty];

    let rawDiff = 0; // Positive = Late, Negative = Early
    let isMiss = true;

    if (closestHit) {
      rawDiff = (tapTime - closestHit.time) * 1000;
    }

    if (closestHit && diffMs < windows[3]) {
        closestHit.processed = true;
        isMiss = false;
        if (diffMs < windows[0]) {
             score = 100; label = "Perfect"; color = "text-white drop-shadow-[0_0_10px_white]";
        } else if (diffMs < windows[1]) {
             score = 90 + Math.floor((windows[1] - diffMs)/(windows[1]-windows[0]) * 10);
             label = "Perfect"; color = `text-${gameConfig.level.color}-200`;
        } else if (diffMs < windows[2]) {
             score = 70 + Math.floor((windows[2] - diffMs)/(windows[2]-windows[1]) * 20);
             label = "Great"; color = `text-${gameConfig.level.color}-300`;
        } else {
             score = 40 + Math.floor((windows[3] - diffMs)/(windows[3]-windows[2]) * 30);
             label = "Good"; color = "text-yellow-200";
        }
    } else {
        score = 0; label = "Miss"; color = "text-red-400/50";
    }

    // Record stats for AI analysis & Chart
    if (closestHit) {
      hitHistory.current.push({
        offset: rawDiff,
        isMiss: isMiss,
        beat: closestHit.beat,
        timestamp: tapTime - gameStartTime.current, // Relative time
        score: score
      });
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;
      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, gameConfig]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') { e.preventDefault(); handleTap(); } 
      else if (e.code === 'Escape') { if (gameState === GameState.PLAYING || gameState === GameState.PAUSED) togglePause(); } 
      else if (e.code === 'KeyQ') { if (gameState === GameState.PAUSED) quitGame(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap, togglePause, gameState, quitGame]);

  // Helper to calculate percentages for chart
  const getTimingStats = (history: HitEvent[]) => {
      const early = history.filter(h => h.offset < -15).length;
      const late = history.filter(h => h.offset > 15).length;
      const total = history.length || 1;
      return {
          earlyPct: (early / total) * 100,
          latePct: (late / total) * 100,
          perfectPct: 100 - ((early + late) / total * 100)
      };
  };

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden font-sans">

      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={gameConfig.level}
            bpm={gameConfig.bpm}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {gameState === GameState.STARTING && gameConfig && (
        <div className="z-10 text-center animate-in fade-in duration-500">
           <div className={`text-lg font-serif italic text-${gameConfig.level.color}-200 mb-4 opacity-70`}>Syncing...</div>
           <div className="text-8xl font-serif text-white tracking-tight">Ready</div>
        </div>
      )}

      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <>
          <div className="absolute top-0 left-0 w-full z-20">
             <div className="h-0.5 w-full bg-white/5">
                <div 
                  className={`h-full bg-${gameConfig.level.color}-300 shadow-[0_0_15px_currentColor] transition-all duration-100 ease-linear`}
                  style={{ width: `${(timeLeft / GAME_DURATION) * 100}%` }}
                ></div>
             </div>
          </div>

          <div className="absolute top-8 left-8 right-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className="text-5xl font-serif text-white/90">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
                 <div className="flex items-center gap-4 mt-2">
                    <span className={`text-xs font-sans tracking-[0.2em] text-${gameConfig.level.color}-200 uppercase`}>{gameConfig.level.name}</span>
                    <span className="text-xs font-serif italic text-slate-500">{gameConfig.difficulty}</span>
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className={`text-5xl font-serif ${stats.averageAccuracy > 95 ? 'text-white' : 'text-slate-300'}`}>
                     {stats.averageAccuracy.toFixed(1)}<span className="text-2xl opacity-50">%</span>
                 </div>
                 <div className="text-xs font-sans text-slate-500 tracking-[0.2em] mt-2 uppercase">Accuracy</div>
             </div>
          </div>

          {gameState === GameState.PLAYING && (
            <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
                {isCountIn ? (
                  <div className="animate-pulse text-center">
                    <div className="text-2xl font-serif italic text-white/50 mb-2">Listen...</div>
                    <div className={`text-6xl font-sans font-bold text-${gameConfig.level.color}-400/80`}>Count In</div>
                  </div>
                ) : (
                  <div className={`text-7xl font-serif italic transition-all duration-500 transform ${lastHit ? 'scale-100 opacity-100 translate-y-0 blur-0' : 'scale-95 opacity-0 translate-y-2 blur-sm'} ${lastHit?.color}`}>
                    {lastHit?.label}
                  </div>
                )}
            </div>
          )}

          {gameState === GameState.PAUSED && (
            <div className="absolute inset-0 z-50 bg-black/40 backdrop-blur-lg flex flex-col items-center justify-center animate-in fade-in duration-500">
                <h2 className="text-5xl font-serif italic text-white mb-12">Paused</h2>
                <div className="flex flex-col space-y-6 w-64 items-center">
                    <button onClick={togglePause} className="text-sm font-sans tracking-[0.3em] text-white hover:scale-105 transition-transform uppercase">
                        Resume
                    </button>
                    <button onClick={quitGame} className="text-xs font-sans tracking-[0.3em] text-slate-500 hover:text-white transition-colors uppercase">
                        Exit
                    </button>
                </div>
            </div>
          )}

          {stats.combo > 5 && gameState === GameState.PLAYING && !isCountIn && (
              <div className="absolute bottom-1/4 z-10 animate-pulse duration-1000">
                  <div className={`text-3xl font-serif italic text-${gameConfig.level.color}-300 opacity-60`}>
                      {stats.combo} Combo
                  </div>
              </div>
          )}
        </>
      )}

      {gameState === GameState.RESULTS && gameConfig && (
        <div className="z-20 w-full max-w-4xl bg-[#0a0a0a]/90 backdrop-blur-xl border border-white/10 p-12 shadow-2xl animate-in fade-in zoom-in-95 duration-700 overflow-hidden flex flex-col">

          <div className="flex justify-between items-end mb-8 border-b border-white/10 pb-6">
            <div>
                <h2 className="text-5xl font-serif italic text-white mb-2">Results</h2>
                <div className={`text-xs font-sans tracking-[0.3em] text-${gameConfig.level.color}-300 uppercase`}>
                    {gameConfig.level.name}
                </div>
            </div>
            <div className="text-right">
                <div className="text-4xl font-serif text-white">{stats.averageAccuracy.toFixed(1)}%</div>
                <div className="text-xs font-sans text-slate-500 tracking-widest uppercase">Accuracy</div>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">

             {/* Left Column: Stats */}
             <div className="space-y-4">
                 <StatRow label="Perfect" count={stats.perfects} color="text-white" />
                 <StatRow label="Great" count={stats.greats} color="text-slate-300" />
                 <StatRow label="Good" count={stats.goods} color="text-slate-400" />
                 <StatRow label="Miss" count={stats.misses} color="text-slate-600" />
                 <div className="pt-6 mt-6 border-t border-white/10">
                    <div className="text-xs font-sans text-slate-500 tracking-widest uppercase mb-2">Total Score</div>
                    <div className={`text-2xl font-serif text-${gameConfig.level.color}-300`}>{Math.floor(stats.totalScore).toLocaleString()}</div>
                 </div>
             </div>

             {/* Middle Column: Detailed Visuals */}
             <div className="lg:col-span-2 flex flex-col space-y-8">

                 {/* Timing Distribution Bar */}
                 <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-sans uppercase tracking-widest text-slate-400">
                        <span>Rushing</span>
                        <span>Perfect</span>
                        <span>Dragging</span>
                    </div>
                    <div className="h-4 w-full bg-white/5 rounded-full overflow-hidden flex">
                        {(() => {
                            const { earlyPct, perfectPct, latePct } = getTimingStats(stats.history);
                            return (
                                <>
                                    <div style={{ width: `${earlyPct}%` }} className="bg-cyan-500/70 h-full"></div>
                                    <div style={{ width: `${perfectPct}%` }} className="bg-white/90 h-full shadow-[0_0_10px_white]"></div>
                                    <div style={{ width: `${latePct}%` }} className="bg-orange-500/70 h-full"></div>
                                </>
                            );
                        })()}
                    </div>
                    <div className="flex justify-between text-xs font-serif italic text-slate-500">
                        <span className="text-cyan-400">{getTimingStats(stats.history).earlyPct.toFixed(0)}%</span>
                        <span className="text-orange-400">{getTimingStats(stats.history).latePct.toFixed(0)}%</span>
                    </div>
                 </div>

                 {/* Timing Deviation Chart */}
                 <div className="flex-1 bg-white/5 rounded-lg border border-white/5 relative p-4 min-h-[150px]">
                    <div className="absolute top-2 left-4 text-[10px] font-sans uppercase tracking-widest text-slate-500">Deviation (ms)</div>
                    <svg className="w-full h-full" viewBox={`0 0 ${GAME_DURATION} 200`} preserveAspectRatio="none">
                        {/* Zero Line */}
                        <line x1="0" y1="100" x2={GAME_DURATION} y2="100" stroke="rgba(255,255,255,0.2)" strokeWidth="1" strokeDasharray="4 4" />

                        {/* Hits */}
                        {stats.history.map((hit, i) => {
                            const y = 100 - hit.offset; // Invert so positive (Late) is down? Or up? Usually up is +Offset. Let's say up is LATE (+), down is EARLY (-). 
                            // Wait, chart Y: 0 is top. 200 is bottom. 100 is center.
                            // if offset is +50 (late), y should be 100 - 50 = 50 (higher). Or 100 + 50 = 150 (lower).
                            // Let's make UP = LATE (+). So 100 - offset. 
                            // Scale: max offset ~100ms. 

                            const cy = 100 - (hit.offset); 
                            // Clamp visually
                            const safeCy = Math.max(10, Math.min(190, cy));

                            const color = hit.offset < -15 ? '#22d3ee' : hit.offset > 15 ? '#f97316' : '#ffffff';
                            const opacity = hit.isMiss ? 0.2 : 0.8;

                            return (
                                <circle 
                                    key={i} 
                                    cx={hit.timestamp} 
                                    cy={safeCy} 
                                    r={hit.score >= 90 ? 2 : 1.5} 
                                    fill={color} 
                                    opacity={opacity}
                                />
                            );
                        })}
                    </svg>
                    {/* Axis Labels */}
                    <div className="absolute bottom-1 right-2 text-[9px] text-slate-600 font-sans">Time →</div>
                    <div className="absolute top-[50%] right-2 transform -translate-y-1/2 text-[9px] text-slate-600 font-sans">0ms</div>
                 </div>

                 {/* Coach Feedback */}
                 <div className="bg-white/5 border-l-2 border-white/20 p-4">
                    <div className="text-[10px] text-slate-400 uppercase tracking-widest mb-2">Master Coach Feedback</div>
                    <div className="text-sm font-serif italic text-slate-200 leading-relaxed">
                        {loadingAI ? <span className="animate-pulse">Analyzing performance dynamics...</span> : `"${aiComment}"`}
                    </div>
                 </div>

             </div>
          </div>

          <div className="flex justify-center gap-8 border-t border-white/10 pt-8 mt-8">
             <button onClick={quitGame} className="text-xs font-sans text-slate-500 hover:text-white transition-colors tracking-[0.2em] uppercase">
                Back to Menu
              </button>
              <button onClick={() => startGame(gameConfig)} className={`text-xs font-sans text-${gameConfig.level.color}-300 hover:text-white transition-colors tracking-[0.2em] uppercase font-bold`}>
                Retry Level
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

const StatRow = ({ label, count, color }: { label: string, count: number, color: string }) => (
    <div className="flex justify-between items-baseline group border-b border-white/5 pb-2 last:border-0">
        <span className="text-slate-500 text-xs font-sans tracking-widest uppercase">{label}</span>
        <span className={`text-xl font-serif ${color}`}>{count}</span>
    </div>
);

export default RhythmEngine;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, ScoreEntry, GameStats, Level, Difficulty, GameConfig, HighScores, HitEvent } from '../types';
import Visualizer from './Visualizer';
import LevelSelector from './LevelSelector';
import { getAICommentary, AnalysisStats } from '../services/geminiService';

// Audio Scheduler Constants
const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // seconds
const GAME_DURATION = 30.0; // seconds

// Scoring Windows (ms) for [Perfect+, Perfect, Great, Good]
const SCORING_WINDOWS = {
  [Difficulty.EASY]:   [40, 70, 130, 200],
  [Difficulty.MEDIUM]: [25, 50, 100, 150],
  [Difficulty.HARD]:   [15, 30, 60, 100]
};

const RhythmEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.IDLE);
  const [gameConfig, setGameConfig] = useState<GameConfig | null>(null);

  const [stats, setStats] = useState<GameStats>({
    totalScore: 0,
    combo: 0,
    maxCombo: 0,
    perfects: 0,
    greats: 0,
    goods: 0,
    misses: 0,
    averageAccuracy: 0,
    history: []
  });
  const [lastHit, setLastHit] = useState<ScoreEntry | null>(null);
  const [aiComment, setAiComment] = useState<string>("");
  const [loadingAI, setLoadingAI] = useState(false);
  const [timeLeft, setTimeLeft] = useState(GAME_DURATION);
  const [isCountIn, setIsCountIn] = useState(false);

  // Audio & Timing Refs
  const audioContext = useRef<AudioContext | null>(null);
  const noiseBuffer = useRef<AudioBuffer | null>(null); 

  const nextNoteTime = useRef<number>(0.0); 
  const nextMetronomeTime = useRef<number>(0.0); 

  const currentBeatInPattern = useRef<number>(0);
  const timerID = useRef<number | null>(null);
  const loopStartTime = useRef<number>(0);
  const gameStartTime = useRef<number>(0); // When scoring actually begins

  // Queue for scoring
  const expectedHits = useRef<Array<{ time: number, beat: number, processed: boolean }>>([]);
  // Detailed hit history for analysis
  const hitHistory = useRef<Array<HitEvent>>([]);
  const [beatTrigger, setBeatTrigger] = useState(0);

  // Initialize Audio
  const initAudio = async () => {
    if (!audioContext.current) {
      audioContext.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContext.current.state === 'suspended') {
      await audioContext.current.resume();
    }

    if (!noiseBuffer.current) {
      const bufferSize = audioContext.current.sampleRate * 2.0; 
      const buffer = audioContext.current.createBuffer(1, bufferSize, audioContext.current.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
      }
      noiseBuffer.current = buffer;
    }
  };

  const playKick = useCallback((time: number) => {
    if (!audioContext.current) return;
    const ctx = audioContext.current;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(50, time + 0.1);

    gain.gain.setValueAtTime(0.5, time); // Softer kick
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }, []);

  const playHiHat = useCallback((time: number) => {
    if (!audioContext.current || !noiseBuffer.current) return;
    const ctx = audioContext.current;

    const source = ctx.createBufferSource();
    source.buffer = noiseBuffer.current;

    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 7000;

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.2, time); // Softer hat
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    source.start(time);
    source.stop(time + 0.1);
  }, []);

  const scheduleNote = useCallback((beatNumber: number, time: number) => {
    // Store beat info (integer part is downbeat, decimal is offbeat)
    expectedHits.current.push({ time: time, beat: beatNumber, processed: false });
    const now = audioContext.current?.currentTime || 0;
    expectedHits.current = expectedHits.current.filter(hit => hit.time > now - 0.5);
    playHiHat(time);
  }, [playHiHat]);

  const endGame = useCallback(() => {
    if (!gameConfig) return;

    // 1. Halt Audio & Loop
    if (timerID.current) window.clearTimeout(timerID.current);
    timerID.current = null;
    if (audioContext.current) audioContext.current.suspend();

    // 2. Derive Stats from History Ref (prevents stale closure issues)
    const history = hitHistory.current;
    const totalHits = history.length;

    // Timing Bias
    const earlyCount = history.filter(h => h.offset < -15).length;
    const lateCount = history.filter(h => h.offset > 15).length;
    const earlyRate = totalHits > 0 ? (earlyCount / totalHits) * 100 : 0;
    const lateRate = totalHits > 0 ? (lateCount / totalHits) * 100 : 0;

    // Specific Miss Types
    const offbeatMisses = history.filter(h => h.isMiss && h.beat % 1 !== 0).length;
    const downbeatMisses = history.filter(h => h.isMiss && h.beat % 1 === 0).length;

    // Trend Analysis
    let trend: 'improving' | 'degrading' | 'stable' = 'stable';
    if (totalHits > 4) {
      const midPoint = Math.floor(totalHits / 2);
      const firstHalf = history.slice(0, midPoint);
      const secondHalf = history.slice(midPoint);

      const getAvgAbsDiff = (arr: typeof history) => arr.reduce((acc, curr) => acc + Math.abs(curr.offset), 0) / (arr.length || 1);
      const firstAvg = getAvgAbsDiff(firstHalf);
      const secondAvg = getAvgAbsDiff(secondHalf);

      if (secondAvg > firstAvg * 1.2) trend = 'degrading';
      else if (secondAvg < firstAvg * 0.8) trend = 'improving';
    }

    // 3. Update State & LocalStorage
    setStats(currentStats => {
        // High Score Logic
        const stored = localStorage.getItem('rhythmPulseScores');
        let scores: HighScores = stored ? JSON.parse(stored) : {};

        const currentLevelScores = scores[gameConfig.level.id] || {};
        const previousEntry = currentLevelScores[gameConfig.difficulty];
        const previousBestScore = typeof previousEntry === 'number' ? previousEntry : (previousEntry?.score || 0);

        if (currentStats.totalScore > previousBestScore) {
          scores = {
            ...scores,
            [gameConfig.level.id]: {
              ...currentLevelScores,
              [gameConfig.difficulty]: {
                  score: Math.floor(currentStats.totalScore),
                  accuracy: currentStats.averageAccuracy
              }
            }
          };
          localStorage.setItem('rhythmPulseScores', JSON.stringify(scores));
        }

        return { ...currentStats, history }; 
    });

    // 4. Trigger AI Analysis (Calculated independently to avoid async state issues)
    // We calculate approximate accuracy from history for the API call to ensure we have data immediately
    const totalScoreAccum = history.reduce((acc, h) => acc + h.score, 0);
    const approxAccuracy = totalHits > 0 ? totalScoreAccum / totalHits : 0;
    const missesCount = history.filter(h => h.isMiss).length;
    const perfectsCount = history.filter(h => h.score >= 90).length;

    const analysisStats: AnalysisStats = {
        perfects: perfectsCount,
        misses: missesCount,
        averageAccuracy: approxAccuracy,
        earlyRate,
        lateRate,
        offbeatMisses,
        downbeatMisses,
        trend
    };

    setLoadingAI(true);
    getAICommentary(analysisStats)
      .then(comment => {
          setAiComment(comment);
          setLoadingAI(false);
      })
      .catch(err => {
          console.error("AI Error", err);
          setLoadingAI(false);
      });

    setGameState(GameState.RESULTS);
  }, [gameConfig]);

  const scheduler = useCallback(() => {
    if (!gameConfig || !audioContext.current || gameState !== GameState.PLAYING) return;
    if (audioContext.current.state === 'suspended') return;

    const currentTime = audioContext.current.currentTime;

    // Timer Logic
    const elapsedTime = currentTime - gameStartTime.current;

    if (elapsedTime < 0) {
        setIsCountIn(true);
        setTimeLeft(GAME_DURATION); // Freeze timer at max
    } else {
        setIsCountIn(false);
        const remaining = Math.max(0, GAME_DURATION - elapsedTime);
        setTimeLeft(remaining);
        if (remaining <= 0) {
            endGame();
            return;
        }
    }

    const beatDuration = 60 / gameConfig.bpm;

    while (nextMetronomeTime.current < currentTime + SCHEDULE_AHEAD_TIME) {
        playKick(nextMetronomeTime.current);
        const timeToNote = (nextMetronomeTime.current - currentTime) * 1000;
        setTimeout(() => {
            if (gameState === GameState.PLAYING) setBeatTrigger(prev => prev + 1);
        }, Math.max(0, timeToNote));
        nextMetronomeTime.current += beatDuration;
    }

    while (nextNoteTime.current < currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(currentBeatInPattern.current, nextNoteTime.current);
        const pattern = gameConfig.level.pattern;
        const currentBeatVal = pattern[currentBeatInPattern.current];
        let nextIndex = (currentBeatInPattern.current + 1) % pattern.length;
        let nextBeatVal = pattern[nextIndex];
        let beatDiff = nextIndex === 0 ? gameConfig.level.loopBeats - currentBeatVal + nextBeatVal : nextBeatVal - currentBeatVal;
        nextNoteTime.current += beatDiff * beatDuration;
        currentBeatInPattern.current = nextIndex;
    }
    timerID.current = window.setTimeout(scheduler, LOOKAHEAD);
  }, [gameConfig, gameState, scheduleNote, playKick, endGame]);

  useEffect(() => {
      let isActive = true;
      if (gameState === GameState.PLAYING && gameConfig && audioContext.current) {
          if (audioContext.current.state === 'suspended') {
              audioContext.current.resume().then(() => { if (isActive) scheduler(); });
          } else { scheduler(); }
      } else if (gameState === GameState.PAUSED && audioContext.current) {
          audioContext.current.suspend();
          if (timerID.current) window.clearTimeout(timerID.current);
      }
      return () => {
          isActive = false;
          if (timerID.current) window.clearTimeout(timerID.current);
      };
  }, [gameState, gameConfig, scheduler]);

  const selectLevel = (config: GameConfig) => {
      setGameConfig(config);
      startGame(config);
  };

  const startGame = async (config: GameConfig) => {
    await initAudio();
    setGameState(GameState.STARTING);
    setStats({
      totalScore: 0, combo: 0, maxCombo: 0, perfects: 0, greats: 0, goods: 0, misses: 0, averageAccuracy: 0, history: []
    });
    setAiComment("");
    setLastHit(null);
    setTimeLeft(GAME_DURATION);
    setIsCountIn(true);
    expectedHits.current = [];
    hitHistory.current = []; // Clear history

    setTimeout(() => {
      if (audioContext.current) {
          const now = audioContext.current.currentTime;
          const beatDuration = 60 / config.bpm;
          const countInDuration = beatDuration * 8; 

          const audioStartTime = now + 0.1;

          nextMetronomeTime.current = audioStartTime; 
          nextNoteTime.current = audioStartTime + (config.level.pattern[0] * beatDuration); 
          loopStartTime.current = audioStartTime;

          gameStartTime.current = audioStartTime + countInDuration; 
          currentBeatInPattern.current = 0;
      }
      setGameState(GameState.PLAYING);
    }, 1000);
  };

  const togglePause = useCallback(() => {
      if (gameState === GameState.PLAYING) setGameState(GameState.PAUSED);
      else if (gameState === GameState.PAUSED) setGameState(GameState.PLAYING);
  }, [gameState]);

  const quitGame = useCallback(() => {
      if (audioContext.current) audioContext.current.suspend();
      setGameState(GameState.IDLE);
      setGameConfig(null);
  }, []);

  const handleTap = useCallback(() => {
    if (gameState !== GameState.PLAYING || !audioContext.current || !gameConfig) return;

    const tapTime = audioContext.current.currentTime;
    if (tapTime < gameStartTime.current) return;

    const activeHits = expectedHits.current.filter(h => !h.processed);

    let closestHit = null;
    let minDiff = Infinity;

    for (const hit of activeHits) {
        const diff = Math.abs(hit.time - tapTime);
        if (diff < minDiff) { minDiff = diff; closestHit = hit; }
    }

    const diffMs = minDiff * 1000;
    let score = 0;
    let label = "Miss";
    let color = "text-red-400";

    const windows = SCORING_WINDOWS[gameConfig.difficulty];

    let rawDiff = 0; // Positive = Late, Negative = Early
    let isMiss = true;

    if (closestHit) {
      rawDiff = (tapTime - closestHit.time) * 1000;
    }

    if (closestHit && diffMs < windows[3]) {
        closestHit.processed = true;
        isMiss = false;
        if (diffMs < windows[0]) {
             score = 100; label = "Perfect"; color = "text-white drop-shadow-[0_0_10px_white]";
        } else if (diffMs < windows[1]) {
             score = 90 + Math.floor((windows[1] - diffMs)/(windows[1]-windows[0]) * 10);
             label = "Perfect"; color = `text-${gameConfig.level.color}-200`;
        } else if (diffMs < windows[2]) {
             score = 70 + Math.floor((windows[2] - diffMs)/(windows[2]-windows[1]) * 20);
             label = "Great"; color = `text-${gameConfig.level.color}-300`;
        } else {
             score = 40 + Math.floor((windows[3] - diffMs)/(windows[3]-windows[2]) * 30);
             label = "Good"; color = "text-yellow-200";
        }
    } else {
        score = 0; label = "Miss"; color = "text-red-400/50";
    }

    // Record stats for AI analysis & Chart
    if (closestHit) {
      hitHistory.current.push({
        offset: rawDiff,
        isMiss: isMiss,
        beat: closestHit.beat,
        timestamp: tapTime - gameStartTime.current, // Relative time
        score: score
      });
    }

    setStats(prev => {
      const newCombo = score > 0 ? prev.combo + 1 : 0;
      const totalTaps = prev.perfects + prev.greats + prev.goods + prev.misses + 1;
      const newAccuracy = (prev.averageAccuracy * (totalTaps - 1) + score) / totalTaps;
      return {
        ...prev,
        totalScore: prev.totalScore + score * (1 + Math.floor(newCombo / 10) * 0.1),
        combo: newCombo,
        maxCombo: Math.max(prev.maxCombo, newCombo),
        perfects: prev.perfects + (score >= 90 ? 1 : 0),
        greats: prev.greats + (score >= 70 && score < 90 ? 1 : 0),
        goods: prev.goods + (score > 10 && score < 70 ? 1 : 0),
        misses: prev.misses + (score <= 10 ? 1 : 0),
        averageAccuracy: newAccuracy
      };
    });

    setLastHit({ score, timestamp: performance.now(), label, color });
  }, [gameState, gameConfig]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') { e.preventDefault(); handleTap(); } 
      else if (e.code === 'Escape') { if (gameState === GameState.PLAYING || gameState === GameState.PAUSED) togglePause(); } 
      else if (e.code === 'KeyQ') { if (gameState === GameState.PAUSED) quitGame(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleTap, togglePause, gameState, quitGame]);

  // Helper to calculate percentages for chart
  const getTimingStats = (history: HitEvent[]) => {
      const early = history.filter(h => h.offset < -15).length;
      const late = history.filter(h => h.offset > 15).length;
      const total = history.length || 1;
      return {
          earlyPct: (early / total) * 100,
          latePct: (late / total) * 100,
          perfectPct: 100 - ((early + late) / total * 100)
      };
  };

  return (
    <div className="relative w-full h-screen flex flex-col items-center justify-center overflow-hidden font-sans">

      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <Visualizer 
            isPlaying={gameState === GameState.PLAYING} 
            level={gameConfig.level}
            bpm={gameConfig.bpm}
            audioContext={audioContext.current}
            loopStartTime={loopStartTime.current}
            lastHitTime={lastHit?.timestamp || null}
            hitScore={lastHit?.score || null}
            beatTrigger={beatTrigger}
        />
      )}

      {gameState === GameState.IDLE && (
         <LevelSelector onSelect={selectLevel} />
      )}

      {gameState === GameState.STARTING && gameConfig && (
        <div className="z-10 text-center animate-in fade-in duration-500">
           <div className={`text-lg font-serif italic text-${gameConfig.level.color}-200 mb-4 opacity-70`}>Syncing...</div>
           <div className="text-8xl font-serif text-white tracking-tight">Ready</div>
        </div>
      )}

      {(gameState === GameState.PLAYING || gameState === GameState.PAUSED) && gameConfig && (
        <>
          <div className="absolute top-0 left-0 w-full z-20">
             <div className="h-0.5 w-full bg-white/5">
                <div 
                  className={`h-full bg-${gameConfig.level.color}-300 shadow-[0_0_15px_currentColor] transition-all duration-100 ease-linear`}
                  style={{ width: `${(timeLeft / GAME_DURATION) * 100}%` }}
                ></div>
             </div>
          </div>

          <div className="absolute top-8 left-8 right-8 flex justify-between items-start z-10 pointer-events-none">
             <div className="flex flex-col items-start">
                 <div className="text-5xl font-serif text-white/90">
                     {Math.floor(stats.totalScore).toLocaleString()}
                 </div>
                 <div className="flex items-center gap-4 mt-2">
                    <span className={`text-xs font-sans tracking-[0.2em] text-${gameConfig.level.color}-200 uppercase`}>{gameConfig.level.name}</span>
                    <span className="text-xs font-serif italic text-slate-500">{gameConfig.difficulty}</span>
                 </div>
             </div>

             <div className="flex flex-col items-end">
                 <div className={`text-5xl font-serif ${stats.averageAccuracy > 95 ? 'text-white' : 'text-slate-300'}`}>
                     {stats.averageAccuracy.toFixed(1)}<span className="text-2xl opacity-50">%</span>
                 </div>
                 <div className="text-xs font-sans text-slate-500 tracking-[0.2em] mt-2 uppercase">Accuracy</div>
             </div>
          </div>

          {gameState === GameState.PLAYING && (
            <div className="z-10 flex flex-col items-center pointer-events-none select-none absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2">
                {isCountIn ? (
                  <div className="animate-pulse text-center">
                    <div className="text-2xl font-serif italic text-white/50 mb-2">Listen...</div>
                    <div className={`text-6xl font-sans font-bold text-${gameConfig.level.color}-400/80`}>Count In</div>
                  </div>
                ) : (
                  <div className={`text-7xl font-serif italic transition-all duration-500 transform ${lastHit ? 'scale-100 opacity-100 translate-y-0 blur-0' : 'scale-95 opacity-0 translate-y-2 blur-sm'} ${lastHit?.color}`}>
                    {lastHit?.label}
                  </div>
                )}
            </div>
          )}

          {gameState === GameState.PAUSED && (
            <div className="absolute inset-0 z-50 bg-black/40 backdrop-blur-lg flex flex-col items-center justify-center animate-in fade-in duration-500">
                <h2 className="text-5xl font-serif italic text-white mb-12">Paused</h2>
                <div className="flex flex-col space-y-6 w-64 items-center">
                    <button onClick={togglePause} className="text-sm font-sans tracking-[0.3em] text-white hover:scale-105 transition-transform uppercase">
                        Resume
                    </button>
                    <button onClick={quitGame} className="text-xs font-sans tracking-[0.3em] text-slate-500 hover:text-white transition-colors uppercase">
                        Exit
                    </button>
                </div>
            </div>
          )}

          {stats.combo > 5 && gameState === GameState.PLAYING && !isCountIn && (
              <div className="absolute bottom-1/4 z-10 animate-pulse duration-1000">
                  <div className={`text-3xl font-serif italic text-${gameConfig.level.color}-300 opacity-60`}>
                      {stats.combo} Combo
                  </div>
              </div>
          )}
        </>
      )}

      {gameState === GameState.RESULTS && gameConfig && (
        <div className="z-20 w-full max-w-4xl bg-[#0a0a0a]/90 backdrop-blur-xl border border-white/10 p-8 shadow-2xl animate-in fade-in zoom-in-95 duration-700 overflow-hidden flex flex-col">

          <div className="flex justify-between items-end mb-6 border-b border-white/10 pb-4">
            <div>
                <h2 className="text-4xl font-serif italic text-white mb-2">Results</h2>
                <div className={`text-[10px] font-sans tracking-[0.3em] text-${gameConfig.level.color}-300 uppercase`}>
                    {gameConfig.level.name}
                </div>
            </div>
            <div className="text-right">
                <div className="text-3xl font-serif text-white">{stats.averageAccuracy.toFixed(1)}%</div>
                <div className="text-[10px] font-sans text-slate-500 tracking-widest uppercase">Accuracy</div>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

             {/* Left Column: Stats */}
             <div className="space-y-3">
                 <StatRow label="Perfect" count={stats.perfects} color="text-white" />
                 <StatRow label="Great" count={stats.greats} color="text-slate-300" />
                 <StatRow label="Good" count={stats.goods} color="text-slate-400" />
                 <StatRow label="Miss" count={stats.misses} color="text-slate-600" />
                 <div className="pt-4 mt-4 border-t border-white/10">
                    <div className="text-[10px] font-sans text-slate-500 tracking-widest uppercase mb-1">Total Score</div>
                    <div className={`text-xl font-serif text-${gameConfig.level.color}-300`}>{Math.floor(stats.totalScore).toLocaleString()}</div>
                 </div>
             </div>

             {/* Middle Column: Detailed Visuals */}
             <div className="lg:col-span-2 flex flex-col space-y-6">

                 {/* Timing Distribution Bar */}
                 <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-sans uppercase tracking-widest text-slate-400">
                        <span>Rushing</span>
                        <span>Perfect</span>
                        <span>Dragging</span>
                    </div>
                    <div className="h-3 w-full bg-white/5 rounded-full overflow-hidden flex">
                        {(() => {
                            const { earlyPct, perfectPct, latePct } = getTimingStats(stats.history);
                            return (
                                <>
                                    <div style={{ width: `${earlyPct}%` }} className="bg-cyan-500/70 h-full"></div>
                                    <div style={{ width: `${perfectPct}%` }} className="bg-white/90 h-full shadow-[0_0_10px_white]"></div>
                                    <div style={{ width: `${latePct}%` }} className="bg-orange-500/70 h-full"></div>
                                </>
                            );
                        })()}
                    </div>
                    <div className="flex justify-between text-[10px] font-serif italic text-slate-500">
                        <span className="text-cyan-400">{getTimingStats(stats.history).earlyPct.toFixed(0)}%</span>
                        <span className="text-orange-400">{getTimingStats(stats.history).latePct.toFixed(0)}%</span>
                    </div>
                 </div>

                 {/* Timing Deviation Chart (Resized smaller) */}
                 <div className="h-32 bg-white/5 rounded-lg border border-white/5 relative p-2">
                    <div className="absolute top-2 left-2 text-[9px] font-sans uppercase tracking-widest text-slate-500">Deviation (ms)</div>
                    <svg className="w-full h-full" viewBox={`0 0 ${GAME_DURATION} 200`} preserveAspectRatio="none">
                        {/* Zero Line */}
                        <line x1="0" y1="100" x2={GAME_DURATION} y2="100" stroke="rgba(255,255,255,0.2)" strokeWidth="1" strokeDasharray="4 4" />

                        {/* Hits */}
                        {stats.history.map((hit, i) => {
                            const cy = 100 - (hit.offset); 
                            const safeCy = Math.max(10, Math.min(190, cy));

                            const color = hit.offset < -15 ? '#22d3ee' : hit.offset > 15 ? '#f97316' : '#ffffff';
                            const opacity = hit.isMiss ? 0.2 : 0.8;

                            return (
                                <circle 
                                    key={i} 
                                    cx={hit.timestamp} 
                                    cy={safeCy} 
                                    r={hit.score >= 90 ? 2 : 1.5} 
                                    fill={color} 
                                    opacity={opacity}
                                />
                            );
                        })}
                    </svg>
                    <div className="absolute bottom-1 right-2 text-[8px] text-slate-600 font-sans">Time →</div>
                 </div>

                 {/* Coach Feedback */}
                 <div className="bg-white/5 border-l-2 border-white/20 p-4">
                    <div className="text-[10px] text-slate-400 uppercase tracking-widest mb-2">Master Coach Feedback</div>
                    <div className="text-sm font-serif italic text-slate-200 leading-relaxed">
                        {loadingAI ? <span className="animate-pulse">Analyzing performance dynamics...</span> : `"${aiComment}"`}
                    </div>
                 </div>

             </div>
          </div>

          <div className="flex justify-center gap-8 border-t border-white/10 pt-6 mt-6">
             <button onClick={quitGame} className="text-[10px] font-sans text-slate-500 hover:text-white transition-colors tracking-[0.2em] uppercase">
                Back to Menu
              </button>
              <button onClick={() => startGame(gameConfig)} className={`text-[10px] font-sans text-${gameConfig.level.color}-300 hover:text-white transition-colors tracking-[0.2em] uppercase font-bold`}>
                Retry Level
              </button>
          </div>
        </div>
      )}
    </div>
  );
};

