import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export interface AnalysisStats {
  perfects: number;
  misses: number;
  averageAccuracy: number;
  earlyRate: number; // Percentage of hits that were early
  lateRate: number; // Percentage of hits that were late
  offbeatMisses: number;
  downbeatMisses: number;
  trend: 'improving' | 'degrading' | 'stable';
}

export const getAICommentary = async (stats: AnalysisStats) => {
  try {
    const prompt = `You are a friendly and encouraging music teacher helping a young student improve their rhythm. Analyze these stats:
    - Accuracy: ${stats.averageAccuracy.toFixed(1)}%
    - Timing: ${stats.earlyRate.toFixed(1)}% Early (too fast), ${stats.lateRate.toFixed(1)}% Late (too slow)
    - Misses: ${stats.misses}
    - Trend: ${stats.trend}

    Write a short, simple message (2 sentences max).
    1. Tell them clearly what they did (e.g., "You were hitting the spacebar a little too early.").
    2. Give them one simple trick to try next time (e.g., "Try nodding your head to the beat," or "Listen to the drums closely").
    3. Use plain language a 10-year-old would understand. Be super positive and helpful!`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
      }
    });

    return response.text || "Keep practicing! Try to tap exactly when you hear the beat.";
  } catch (error) {
    console.error("Gemini Commentary Error:", error);
    return "Listen closely to the music and try again!";
  }
};

