              const time = now + loopOffset + (note.beat * beatDuration);

              const osc = ctx.createOscillator();
              const gain = ctx.createGain();

              // Use Clave Tuning: Perfect Fourth
              const freq = (note.hand === 'left') ? 1800 : 2400;

              osc.type = 'sine';
