                >
                    {cat}
                    {activeCategory === cat && (
                        <div className="absolute -bottom-[17px] left-0 w-full h-[2px] bg-gradient-to-r from-transparent via-white to-transparent shadow-[0_0_15px_white]"></div>
                    )}
